// ── CONFIRM DIALOG (replaces window.confirm which is blocked in iframes) ────────
function ConfirmDialog({ message, onConfirm, onCancel }) {
  return (
    <div style={{ position:"fixed",inset:0,background:"rgba(20,15,10,0.6)",zIndex:500,display:"flex",alignItems:"center",justifyContent:"center",padding:16,backdropFilter:"blur(3px)" }}>
      <div style={{ background:C.surface,borderRadius:16,padding:"26px 28px",maxWidth:360,width:"100%",boxShadow:"0 24px 80px rgba(0,0,0,0.3)",textAlign:"center" }}>
        <div style={{ fontSize:32,marginBottom:12 }}>🗑</div>
        <div style={{ fontSize:15,fontFamily:fontSans,fontWeight:600,color:C.text,marginBottom:20 }}>{message}</div>
        <div style={{ display:"flex",gap:10,justifyContent:"center" }}>
          <Btn variant="secondary" onClick={onCancel}>Cancelar</Btn>
          <Btn variant="danger" onClick={onConfirm}>Eliminar</Btn>
        </div>
      </div>
    </div>
  );
}

function useConfirm() {
  const [state, setState] = useState(null); // { message, resolve }
  const confirm = (message) => new Promise(resolve => setState({ message, resolve }));
  const handleConfirm = () => { state?.resolve(true);  setState(null); };
  const handleCancel  = () => { state?.resolve(false); setState(null); };
  const dialog = state ? <ConfirmDialog message={state.message} onConfirm={handleConfirm} onCancel={handleCancel} /> : null;
  return [confirm, dialog];
}

