// ── AI INVOICE SCANNER ────────────────────────────────────────────────────────
// Detect the real MIME type from a data-URL prefix, with a safe fallback.
// Supported image types by the API: image/jpeg, image/png, image/gif, image/webp
const MIME_REMAP = { "image/jpg": "image/jpeg" };
function detectMime(dataUrl) {
  const m = dataUrl.match(/^data:([^;]+);base64,/);
  if (!m) return "image/jpeg";
  const raw = m[1].toLowerCase();
  return MIME_REMAP[raw] || raw;
}

function InvoiceScanner({ properties, onResult, onClose }) {
  const [stage, setStage]         = useState("upload"); // upload | scanning | result
  // fileInfo: { dataUrl, base64, mime, isPdf, name }
  const [fileInfo, setFileInfo]   = useState(null);
  const [form, setForm]           = useState({});
  const [highlightFields, setHighlightFields] = useState([]);
  const [error, setError]         = useState(null);
  const [apiError, setApiError]   = useState(null); // raw API error for debug
  const imgRef  = useRef();
  const pdfRef  = useRef();

  const loadFile = file => {
    if (!file) return;
    const isPdf = file.type === "application/pdf";
    const validImage = ["image/jpeg","image/png","image/gif","image/webp","image/jpg"].includes(file.type);
    if (!isPdf && !validImage) {
      setError("Formato no admitido. Sube una imagen (JPG, PNG, WEBP) o un PDF.");
      return;
    }
    setError(null);
    const reader = new FileReader();
    reader.onload = e => {
      const dataUrl = e.target.result;
      const base64  = dataUrl.split(",")[1];
      const mime    = isPdf ? "application/pdf" : detectMime(dataUrl);
      setFileInfo({ dataUrl, base64, mime, isPdf, name: file.name });
    };
    reader.readAsDataURL(file);
  };

  const scan = async () => {
    if (!fileInfo) return;
    setStage("scanning");
    setError(null);
    setApiError(null);
    try {
      const today = new Date().toISOString().split("T")[0];
      const systemPrompt = `Eres un experto en contabilidad española. Extrae los datos de la factura o recibo.
Responde ÚNICAMENTE con un objeto JSON válido, sin texto adicional ni bloques de código markdown.
Si un campo no aparece en el documento usa null. Campos requeridos:
{
  "description": "descripción breve del concepto o servicio",
  "supplier": "nombre del proveedor o empresa emisora",
  "supplierNif": "NIF o CIF del proveedor",
  "invoiceNum": "número de factura o referencia",
  "date": "fecha en formato YYYY-MM-DD",
  "amount": importe TOTAL numérico incluyendo IVA,
  "baseAmount": base imponible numérica sin IVA,
  "vatAmount": importe del IVA numérico,
  "vatPct": porcentaje de IVA numérico (ej: 21),
  "category": una de: "Reparación","Comunidad","Seguro","IBI","Hipoteca cuota","Suministros","Fontanería","Electricidad","Pintura / Reformas","Agencia inmobiliaria","Notaría / Gestoría","Limpieza","Otro",
  "paymentMethod": una de: "Transferencia","Domiciliación","Tarjeta","Efectivo","Bizum","Otro",
  "notes": "observaciones relevantes o null"
}`;

      // Build content block depending on file type
      // PDFs → type "document" with media_type "application/pdf"
      // Images → type "image" with the real detected mime
      const fileBlock = fileInfo.isPdf
        ? { type: "document", source: { type: "base64", media_type: "application/pdf", data: fileInfo.base64 } }
        : { type: "image",    source: { type: "base64", media_type: fileInfo.mime,              data: fileInfo.base64 } };

      const resp = await fetch("https://api.anthropic.com/v1/messages", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          model: "claude-sonnet-4-20250514",
          max_tokens: 1024,
          system: systemPrompt,
          messages: [{
            role: "user",
            content: [
              fileBlock,
              { type: "text", text: `Analiza este documento y extrae los datos de la factura. Hoy es ${today}. Responde SOLO con el JSON, sin nada más.` }
            ]
          }]
        })
      });

      const json = await resp.json();

      // Surface API-level errors clearly
      if (json.type === "error" || json.error) {
        const msg = json.error?.message || JSON.stringify(json);
        setApiError(msg);
        throw new Error(msg);
      }

      const rawText = (json.content || []).map(b => b.text || "").join("").trim();
      if (!rawText) throw new Error("La IA no devolvió ningún texto.");

      // Strip optional markdown fences
      const clean = rawText.replace(/^```(?:json)?\s*/i, "").replace(/\s*```$/i, "").trim();
      const parsed = JSON.parse(clean);

      const detected = [];
      const newForm  = { propertyId: properties[0]?.id || "", status: "paid", deductible: true };
      ["description","supplier","supplierNif","invoiceNum","date","amount","baseAmount","vatAmount","vatPct","category","paymentMethod","notes"].forEach(k => {
        if (parsed[k] !== null && parsed[k] !== undefined && String(parsed[k]).trim() !== "") {
          newForm[k] = String(parsed[k]);
          detected.push(k);
        }
      });

      setForm(newForm);
      setHighlightFields(detected);
      setStage("result");
    } catch (err) {
      setError("No se pudo analizar el documento. " + (err.message || String(err)));
      setStage("upload");
    }
  };

  const clear = e => { e?.stopPropagation(); setFileInfo(null); setError(null); setApiError(null); };
  const save  = () => { onResult(form); onClose(); };

  // ── Upload stage ──
  if (stage === "upload") return (
    <Modal title="✨ Escanear factura con IA" onClose={onClose} wide>
      {/* Drop zone */}
      <div
        onDragOver={e => e.preventDefault()}
        onDrop={e => { e.preventDefault(); loadFile(e.dataTransfer.files[0]); }}
        onClick={() => !fileInfo && imgRef.current.click()}
        style={{ border: `2px dashed ${fileInfo ? C.accent : C.border}`, borderRadius: 14, padding: fileInfo ? 16 : 32, cursor: fileInfo ? "default" : "pointer", background: fileInfo ? C.accentLight : C.surfaceAlt, transition: "all 0.2s", textAlign: "center", marginBottom: 14, position: "relative" }}
      >
        {fileInfo ? (
          <div>
            {fileInfo.isPdf ? (
              <div style={{ display: "flex", alignItems: "center", gap: 14, justifyContent: "center", padding: "8px 0" }}>
                <div style={{ fontSize: 48 }}>📄</div>
                <div style={{ textAlign: "left" }}>
                  <div style={{ fontWeight: 700, fontSize: 15, fontFamily: fontSans, color: C.text }}>{fileInfo.name}</div>
                  <div style={{ fontSize: 12, color: C.textMuted, fontFamily: fontSans, marginTop: 3 }}>PDF listo para analizar</div>
                </div>
              </div>
            ) : (
              <img src={fileInfo.dataUrl} alt="Factura" style={{ maxHeight: 280, maxWidth: "100%", borderRadius: 8, objectFit: "contain" }} />
            )}
            <button onClick={clear} style={{ position: "absolute", top: 10, right: 10, background: "rgba(0,0,0,0.55)", color: "#fff", border: "none", borderRadius: "50%", width: 26, height: 26, cursor: "pointer", fontSize: 15, display: "flex", alignItems: "center", justifyContent: "center" }}>×</button>
          </div>
        ) : (
          <div>
            <div style={{ fontSize: 48, marginBottom: 12 }}>📁</div>
            <div style={{ fontWeight: 700, fontSize: 16, fontFamily: fontSans, color: C.text, marginBottom: 6 }}>Arrastra o haz clic para subir</div>
            <div style={{ fontSize: 13, color: C.textMuted, fontFamily: fontSans }}>Imágenes (JPG, PNG, WEBP) · PDF</div>
          </div>
        )}
      </div>

      {/* Two separate inputs so iPhone allows choosing camera OR PDF */}
      <div style={{ display: "flex", gap: 10, marginBottom: 14 }}>
        <button onClick={() => imgRef.current.click()} style={{ flex: 1, padding: "10px", borderRadius: 9, border: `1.5px solid ${C.border}`, background: C.surface, cursor: "pointer", fontFamily: fontSans, fontSize: 13, fontWeight: 600, color: C.textMid }}>
          📷 Foto / imagen
        </button>
        <button onClick={() => pdfRef.current.click()} style={{ flex: 1, padding: "10px", borderRadius: 9, border: `1.5px solid ${C.border}`, background: C.surface, cursor: "pointer", fontFamily: fontSans, fontSize: 13, fontWeight: 600, color: C.textMid }}>
          📄 Subir PDF
        </button>
      </div>

      {/* Hidden inputs — image keeps capture for iPhone camera; pdf has no capture */}
      <input ref={imgRef} type="file" accept="image/jpeg,image/png,image/webp,image/gif" capture="environment" onChange={e => loadFile(e.target.files[0])} style={{ display: "none" }} />
      <input ref={pdfRef} type="file" accept="application/pdf"                            onChange={e => loadFile(e.target.files[0])} style={{ display: "none" }} />

      {error    && <div style={{ background: C.redBg,  color: C.red,  padding: "10px 14px", borderRadius: 8, fontSize: 13, fontFamily: fontSans, marginBottom: 10 }}>⚠ {error}</div>}
      {apiError && <details style={{ marginBottom: 10 }}><summary style={{ fontSize: 12, color: C.textMuted, cursor: "pointer", fontFamily: fontSans }}>Detalle del error técnico</summary><pre style={{ fontSize: 11, color: C.red, background: C.redBg, borderRadius: 6, padding: 10, overflowX: "auto", marginTop: 6, whiteSpace: "pre-wrap" }}>{apiError}</pre></details>}

      <div style={{ display: "flex", gap: 10, justifyContent: "flex-end" }}>
        <Btn variant="secondary" onClick={onClose}>Cancelar</Btn>
        <Btn disabled={!fileInfo} style={{ opacity: fileInfo ? 1 : 0.4 }} onClick={scan}>✨ Analizar con IA</Btn>
      </div>
    </Modal>
  );

  // ── Scanning stage ──
  if (stage === "scanning") return (
    <Modal title="Analizando factura..." onClose={onClose}>
      <div style={{ textAlign: "center", padding: "32px 0 24px" }}>
        <div style={{ fontSize: 52, marginBottom: 16, animation: "spin 1.5s linear infinite", display: "inline-block" }}>✨</div>
        <div style={{ fontWeight: 700, fontSize: 16, fontFamily: fontSans, color: C.text, marginBottom: 8 }}>La IA está leyendo la factura</div>
        <div style={{ fontSize: 13, color: C.textMuted, fontFamily: fontSans }}>Extrayendo proveedor, importes, IVA, fecha...</div>
        <style>{`@keyframes spin { from { transform: rotate(0deg); } to { transform: rotate(360deg); } }`}</style>
      </div>
    </Modal>
  );

  // ── Result stage ──
  return (
    <Modal title="✨ Factura detectada — revisa y guarda" onClose={onClose} extraWide>
      <ExpenseForm
        form={form}
        setForm={setForm}
        properties={properties}
        highlightFields={highlightFields}
        invoicePreview={fileInfo?.isPdf ? null : fileInfo?.dataUrl}
        pdfName={fileInfo?.isPdf ? fileInfo?.name : null}
        onSave={save}
        onCancel={onClose}
        saveLabel="✓ Guardar gasto"
      />
    </Modal>
  );
}

// ═══════════════════════════════════════════════════════════════════════════════
// EXPENSES PAGE
// ═══════════════════════════════════════════════════════════════════════════════
function Expenses({ data, setData }) {
  const [modal, setModal]         = useState(null); // null | "add" | "edit" | "scan" | "dupes"
  const [form, setForm]           = useState({});
  const [editId, setEditId]       = useState(null);
  const [propFilter, setPropFilter] = useState("all");
  const [catFilter, setCatFilter] = useState("all");
  const [yearFilter, setYearFilter] = useState("all");
  const [confirm, confirmDialog] = useConfirm();
  // Duplicates modal state
  const [dupSelected, setDupSelected] = useState({}); // id -> bool

  const allYears = [...new Set(data.expenses.map(e=>e.date?.slice(0,4)).filter(Boolean))].sort((a,b)=>b-a);

  const defaultForm = () => ({ propertyId: data.properties[0]?.id, category: "Reparación", status: "paid", deductible: true, paymentMethod: "Transferencia", date: new Date().toISOString().split("T")[0] });

  const openAdd  = ()  => { setForm(defaultForm()); setModal("add"); };
  const openEdit = (e) => { setForm({ ...e }); setEditId(e.id); setModal("edit"); };
  const openScan = ()  => setModal("scan");

  const saveAdd = () => {
    setData(d => ({ ...d, expenses: [...d.expenses, { ...form, id: Date.now(), amount: +form.amount || 0, baseAmount: form.baseAmount ? +form.baseAmount : null, vatAmount: form.vatAmount ? +form.vatAmount : null, vatPct: form.vatPct ? +form.vatPct : null, propertyId: +form.propertyId }] }));
    setModal(null);
  };

  const saveEdit = () => {
    setData(d => ({ ...d, expenses: d.expenses.map(e => e.id === editId ? { ...form, id: editId, amount: +form.amount || 0, baseAmount: form.baseAmount ? +form.baseAmount : null, vatAmount: form.vatAmount ? +form.vatAmount : null, vatPct: form.vatPct ? +form.vatPct : null, propertyId: +form.propertyId } : e) }));
    setModal(null);
  };

  const saveScan = (prefilled) => {
    setData(d => ({ ...d, expenses: [...d.expenses, { ...prefilled, id: Date.now(), amount: +prefilled.amount || 0, baseAmount: prefilled.baseAmount ? +prefilled.baseAmount : null, vatAmount: prefilled.vatAmount ? +prefilled.vatAmount : null, vatPct: prefilled.vatPct ? +prefilled.vatPct : null, propertyId: +prefilled.propertyId }] }));
  };

  const isAutoGenerated = (e) => e.autoMortgage || e.autoInsurance || e.autoRecurring;

  const del = async (id) => {
    const expense = data.expenses.find(e => e.id === id);
    const isAuto = expense && isAutoGenerated(expense);
    const msg = isAuto
      ? "Este gasto fue generado automáticamente. ¿Eliminar y no volver a generarlo?"
      : "¿Eliminar este gasto?";
    if (await confirm(msg)) {
      setData(d => {
        const newSuppressed = isAuto
          ? [...new Set([...(d.suppressedAutoIds || []), id])]
          : (d.suppressedAutoIds || []);
        return { ...d, expenses: d.expenses.filter(e => e.id !== id), suppressedAutoIds: newSuppressed };
      });
    }
  };

  // ── Duplicate detection ──────────────────────────────────────────────────────
  const findDuplicates = () => {
    const groups = {};
    data.expenses.forEach(e => {
      // Key: same amount + same date + same propertyId + same description (case-insensitive trim)
      const key = `${Number(e.amount).toFixed(2)}|${e.date || ""}|${e.propertyId}|${(e.description || "").trim().toLowerCase()}`;
      if (!groups[key]) groups[key] = [];
      groups[key].push(e);
    });
    return Object.values(groups).filter(g => g.length > 1);
  };

  const openDupes = () => {
    const groups = findDuplicates();
    if (groups.length === 0) return; // button is disabled if no dupes
    // Pre-select all but first in each group for deletion
    const sel = {};
    groups.forEach(g => g.slice(1).forEach(e => { sel[e.id] = true; }));
    setDupSelected(sel);
    setModal("dupes");
  };

  const deleteDupes = async () => {
    const toDelete = Object.keys(dupSelected).filter(id => dupSelected[id]);
    if (toDelete.length === 0) return;
    if (await confirm(`¿Eliminar ${toDelete.length} gasto${toDelete.length > 1 ? "s" : ""} duplicado${toDelete.length > 1 ? "s" : ""}?`)) {
      setData(d => {
        const toDeleteSet = new Set(toDelete);
        const autoIds = toDelete.filter(id => {
          const e = d.expenses.find(x => String(x.id) === String(id));
          return e && isAutoGenerated(e);
        });
        const newSuppressed = [...new Set([...(d.suppressedAutoIds || []), ...autoIds])];
        return { ...d, expenses: d.expenses.filter(e => !toDeleteSet.has(String(e.id))), suppressedAutoIds: newSuppressed };
      });
      setModal(null);
    }
  };

  const filtered = data.expenses
    .filter(e => propFilter === "all" || e.propertyId === +propFilter)
    .filter(e => catFilter === "all" || e.category === catFilter)
    .filter(e => yearFilter === "all" || e.date?.startsWith(yearFilter))
    .sort((a, b) => new Date(b.date) - new Date(a.date));

  const totalAll  = filtered.reduce((s, e) => s + e.amount, 0);
  const totalDed  = data.expenses.filter(e => e.deductible && e.status === "paid" && (yearFilter === "all" || e.date?.startsWith(yearFilter))).reduce((s, e) => s + e.amount, 0);
  const categories = [...new Set(data.expenses.map(e => e.category))];

  const dupGroups = findDuplicates();
  const dupCount = dupGroups.reduce((s, g) => s + g.length - 1, 0);

  return (
    <div>
      <SH title="Gastos"
        action={
          <div style={{ display: "flex", gap: 10 }}>
            {dupCount > 0 && (
              <Btn variant="danger" onClick={openDupes}>🔍 {dupCount} duplicado{dupCount > 1 ? "s" : ""}</Btn>
            )}
            <Btn variant="purple" onClick={openScan}>✨ Escanear factura</Btn>
            <Btn onClick={openAdd}>+ Añadir gasto</Btn>
          </div>
        }
      />

      {/* Summary strip */}
      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(165px, 1fr))", gap: 13, marginBottom: 22 }}>
        {data.properties.map(p => {
          const total = data.expenses.filter(e => e.propertyId === p.id && (yearFilter === "all" || e.date?.startsWith(yearFilter))).reduce((s, e) => s + e.amount, 0);
          return (
            <div key={p.id} style={{ background: C.surface, borderRadius: 11, padding: "14px 16px", border: `1px solid ${C.border}`, borderLeft: `4px solid ${p.color}` }}>
              <div style={{ fontSize: 11, color: C.textMuted, fontFamily: fontSans, fontWeight: 700, textTransform: "uppercase" }}>{p.name}</div>
              <div style={{ fontSize: 20, fontWeight: 800, fontFamily: fontSans, color: C.text, marginTop: 3 }}>{fmt(total)}</div>
            </div>
          );
        })}
        <div style={{ background: C.text, borderRadius: 11, padding: "14px 16px" }}>
          <div style={{ fontSize: 11, color: "rgba(255,255,255,0.5)", fontFamily: fontSans, fontWeight: 700, textTransform: "uppercase" }}>Total</div>
          <div style={{ fontSize: 20, fontWeight: 800, fontFamily: fontSans, color: "#fff", marginTop: 3 }}>{fmt(data.expenses.filter(e => yearFilter === "all" || e.date?.startsWith(yearFilter)).reduce((s, e) => s + e.amount, 0))}</div>
        </div>
        <div style={{ background: C.greenBg, borderRadius: 11, padding: "14px 16px", border: `1px solid ${C.border}` }}>
          <div style={{ fontSize: 11, color: C.green, fontFamily: fontSans, fontWeight: 700, textTransform: "uppercase" }}>Deducibles</div>
          <div style={{ fontSize: 20, fontWeight: 800, fontFamily: fontSans, color: C.green, marginTop: 3 }}>{fmt(totalDed)}</div>
        </div>
      </div>

      {/* Pending expenses banner */}
      {(() => {
        const pending = data.expenses.filter(e => e.status === "pending").sort((a,b) => new Date(a.date)-new Date(b.date));
        if (pending.length === 0) return null;
        return (
          <div style={{ background:C.amberBg, border:`1.5px solid #f6d28a`, borderRadius:12, padding:"14px 18px", marginBottom:18 }}>
            <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", marginBottom:10, flexWrap:"wrap", gap:8 }}>
              <div style={{ display:"flex", alignItems:"center", gap:8 }}>
                <span style={{ fontSize:18 }}>⏳</span>
                <div style={{ fontWeight:700, fontSize:14, fontFamily:fontSans, color:C.amber }}>Gastos pendientes de pago — {pending.length} {pending.length===1?"vencimiento":"vencimientos"}</div>
              </div>
              <span style={{ fontWeight:800, fontSize:15, fontFamily:fontSans, color:C.amber }}>{fmt(pending.reduce((s,e)=>s+e.amount,0))}</span>
            </div>
            <div style={{ display:"flex", flexDirection:"column", gap:7 }}>
              {pending.slice(0,5).map(e => {
                const prop = data.properties.find(p=>p.id===e.propertyId);
                const isOverdue = new Date(e.date+"T23:59:59") < new Date();
                return (
                  <div key={e.id} style={{ display:"flex", alignItems:"center", gap:12, background:C.surface, borderRadius:9, padding:"9px 13px", border:`1px solid ${C.border}` }}>
                    <div style={{ flex:1, minWidth:0 }}>
                      <div style={{ fontWeight:600, fontSize:13, fontFamily:fontSans, overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap" }}>{e.description}</div>
                      <div style={{ fontSize:11, color:C.textMuted, fontFamily:fontSans, marginTop:2 }}>
                        {prop?.name} · <span style={{ color: isOverdue?C.red:C.amber, fontWeight:700 }}>{isOverdue?"Vencido":"Vence"} {fmtDateShort(e.date)}</span>
                        {e.autoInsurance && " · 🛡 Seguro"}{e.autoRecurring && " · 🔁 Recurrente"}
                      </div>
                    </div>
                    <div style={{ fontWeight:800, fontSize:14, color:C.amber, fontFamily:fontSans, whiteSpace:"nowrap" }}>{fmt(e.amount)}</div>
                    <button onClick={()=>setData(d=>{
  const exp = d.expenses.map(x=>x.id===e.id?{...x,status:"paid"}:x);
  const ins = e.autoInsurance && e.insuranceId
    ? (d.insurances||[]).map(i=>i.id===e.insuranceId?advanceInsuranceDate(i):i)
    : d.insurances;
  return {...d, expenses:exp, insurances:ins};
})} style={{ background:C.greenBg, color:C.green, border:"none", borderRadius:7, padding:"5px 10px", cursor:"pointer", fontSize:12, fontFamily:fontSans, fontWeight:700, whiteSpace:"nowrap" }}>✓ Pagar</button>
                  </div>
                );
              })}
              {pending.length > 5 && <div style={{ fontSize:12, color:C.amber, fontFamily:fontSans, textAlign:"center", paddingTop:4 }}>y {pending.length-5} más...</div>}
            </div>
          </div>
        );
      })()}

      {/* Filters */}
      <div style={{ display: "flex", gap: 10, marginBottom: 16, flexWrap: "wrap", alignItems: "center" }}>
        <select value={yearFilter} onChange={e => setYearFilter(e.target.value)} style={{ ...inputSt, width: "auto", padding: "7px 12px" }}>
          <option value="all">Todos los años</option>
          {allYears.map(y => <option key={y} value={y}>{y}</option>)}
        </select>
        <select value={propFilter} onChange={e => setPropFilter(e.target.value)} style={{ ...inputSt, width: "auto", padding: "7px 12px" }}>
          <option value="all">Todos los pisos</option>
          {data.properties.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
        </select>
        <select value={catFilter} onChange={e => setCatFilter(e.target.value)} style={{ ...inputSt, width: "auto", padding: "7px 12px" }}>
          <option value="all">Todas las categorías</option>
          {categories.map(c => <option key={c} value={c}>{c}</option>)}
        </select>
        <span style={{ marginLeft: "auto", fontFamily: fontSans, fontSize: 14, color: C.textMuted }}>Mostrando: <strong style={{ color: C.text }}>{fmt(totalAll)}</strong></span>
      </div>

      {/* Table */}
      <Card>
        <div style={{ overflowX: "auto" }}>
          <table style={{ width: "100%", borderCollapse: "collapse", minWidth: 720 }}>
            <TH cols={["Descripción", "Proveedor", "Nº Factura", "Categoría", "Piso", "Fecha", "Base / IVA", "Total", "Ded.", "Estado", ""]} />
            <tbody>
              {filtered.map((e, i) => {
                const prop = data.properties.find(p => p.id === e.propertyId);
                const isAutoIns = e.autoInsurance === true;
                const isAutoRec = e.autoRecurring === true;
                const isRecPaid = e.isRecurring && !e.autoRecurring;
                const rowBg = e.status === "pending" ? (i%2 ? "#fffbf5" : "#fffdf9") : (i % 2 ? C.surfaceAlt : C.surface);
                return (
                  <tr key={e.id} style={{ borderBottom: `1px solid ${C.border}`, background: rowBg }}>
                    <td style={{ padding: "11px 14px", fontSize: 13, fontWeight: 600, fontFamily: fontSans, maxWidth: 200 }}>
                      <div style={{ overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{e.description}</div>
                      <div style={{ display:"flex", gap:4, flexWrap:"wrap", marginTop:3 }}>
                        {isAutoIns && <span style={{ fontSize:10, background:C.blueBg, color:C.blue, padding:"1px 6px", borderRadius:8, fontWeight:700 }}>🛡 Seguro</span>}
                        {isAutoRec && <span style={{ fontSize:10, background:C.purpleBg, color:C.purple, padding:"1px 6px", borderRadius:8, fontWeight:700 }}>🔁 Recurrente</span>}
                        {isRecPaid && e.nextDueDate && <span style={{ fontSize:10, background:C.greenBg, color:C.green, padding:"1px 6px", borderRadius:8, fontWeight:700 }}>🔁 Próx: {fmtDateShort(e.nextDueDate)}</span>}
                      </div>
                    </td>
                    <td style={{ padding: "11px 14px", fontSize: 12, fontFamily: fontSans, color: C.textMid, maxWidth: 130 }}>
                      <div style={{ overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{e.supplier || "—"}</div>
                      {e.supplierNif && <div style={{ fontSize: 10, color: C.textMuted }}>{e.supplierNif}</div>}
                    </td>
                    <td style={{ padding: "11px 14px", fontSize: 12, fontFamily: fontSans, color: C.textMuted }}>{e.invoiceNum || "—"}</td>
                    <td style={{ padding: "11px 14px" }}>
                      <span style={{ fontSize: 11, background: C.bg, padding: "2px 8px", borderRadius: 12, color: C.textMid, fontWeight: 700, fontFamily: fontSans, whiteSpace: "nowrap" }}>{e.category}</span>
                    </td>
                    <td style={{ padding: "11px 14px" }}>
                      {prop && <span style={{ fontSize: 11, background: (prop.color || C.accent) + "22", color: prop.color || C.accent, padding: "2px 8px", borderRadius: 12, fontWeight: 700, fontFamily: fontSans }}>{prop.name}</span>}
                    </td>
                    <td style={{ padding: "11px 14px", fontSize: 12, color: C.textMuted, fontFamily: fontSans, whiteSpace: "nowrap" }}>{fmtDateShort(e.date)}</td>
                    <td style={{ padding: "11px 14px", fontSize: 12, fontFamily: fontSans, color: C.textMid }}>
                      {e.baseAmount ? <span>{fmt(e.baseAmount)}<br/><span style={{ color: C.textMuted }}>+{fmt(e.vatAmount || 0)} IVA{e.vatPct ? ` (${e.vatPct}%)` : ""}</span></span> : <span style={{ color: C.textMuted }}>—</span>}
                    </td>
                    <td style={{ padding: "11px 14px", fontSize: 14, fontWeight: 800, color: C.red, fontFamily: fontSans, whiteSpace: "nowrap" }}>-{fmt(e.amount)}</td>
                    <td style={{ padding: "11px 14px", textAlign: "center" }}>{e.deductible ? <span style={{ color: C.green, fontSize: 15 }}>✓</span> : <span style={{ color: C.textMuted }}>—</span>}</td>
                    <td style={{ padding: "11px 14px" }}><Badge status={e.status} /></td>
                    <td style={{ padding: "11px 14px" }}>
                      <div style={{ display: "flex", gap: 5, flexWrap:"wrap" }}>
                        {e.status === "pending" && (
                          <button onClick={() => setData(d=>{
  const exp = d.expenses.map(x=>x.id===e.id?{...x,status:"paid"}:x);
  const ins = e.autoInsurance && e.insuranceId
    ? (d.insurances||[]).map(i=>i.id===e.insuranceId?advanceInsuranceDate(i):i)
    : d.insurances;
  return {...d, expenses:exp, insurances:ins};
})} style={{ fontSize:11,padding:"4px 8px",borderRadius:6,border:"none",background:C.greenBg,cursor:"pointer",color:C.green,fontFamily:fontSans,fontWeight:700 }} title="Marcar como pagado">✓ Pagar</button>
                        )}
                        <button onClick={() => openEdit(e)} style={{ fontSize: 11, padding: "4px 8px", borderRadius: 6, border: `1px solid ${C.border}`, background: C.surface, cursor: "pointer", color: C.textMid, fontFamily: fontSans }} title="Editar">✏</button>
                        <button onClick={() => del(e.id)} style={{ fontSize: 11, padding: "4px 8px", borderRadius: 6, border: "none", background: C.redBg, cursor: "pointer", color: C.red, fontFamily: fontSans }} title="Eliminar">🗑</button>
                      </div>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
        {filtered.length === 0 && <div style={{ padding: 32, textAlign: "center", color: C.textMuted, fontFamily: fontSans }}>Sin gastos con este filtro</div>}
      </Card>

      {/* Modals */}
      {modal === "add" && (
        <Modal title="Añadir gasto" onClose={() => setModal(null)} wide>
          <ExpenseForm form={form} setForm={setForm} properties={data.properties} onSave={saveAdd} onCancel={() => setModal(null)} />
        </Modal>
      )}

      {modal === "edit" && (
        <Modal title="Editar gasto" onClose={() => setModal(null)} wide>
          <ExpenseForm form={form} setForm={setForm} properties={data.properties} onSave={saveEdit} onCancel={() => setModal(null)} saveLabel="Guardar cambios" />
        </Modal>
      )}

      {modal === "scan" && (
        <InvoiceScanner
          properties={data.properties}
          onResult={prefilled => { saveScan(prefilled); }}
          onClose={() => setModal(null)}
        />
      )}

      {/* Duplicates modal */}
      {modal === "dupes" && (
        <Modal title={`🔍 Gastos duplicados detectados`} onClose={() => setModal(null)} extraWide>
          <div style={{ marginBottom: 14, padding: "10px 14px", background: C.amberBg, borderRadius: 10, fontSize: 13, fontFamily: fontSans, color: C.amber, fontWeight: 600 }}>
            Se han encontrado <strong>{dupGroups.length} grupo{dupGroups.length > 1 ? "s" : ""}</strong> de gastos con el mismo importe, fecha y descripción. Marca los que quieres eliminar.
          </div>
          <div style={{ display: "flex", flexDirection: "column", gap: 16, maxHeight: 480, overflowY: "auto", paddingRight: 4 }}>
            {dupGroups.map((group, gi) => {
              const prop = data.properties.find(p => p.id === group[0].propertyId);
              return (
                <div key={gi} style={{ border: `1.5px solid ${C.border}`, borderRadius: 12, overflow: "hidden" }}>
                  <div style={{ background: C.surfaceAlt, padding: "8px 14px", borderBottom: `1px solid ${C.border}`, display: "flex", alignItems: "center", gap: 10 }}>
                    <span style={{ fontWeight: 700, fontSize: 13, fontFamily: fontSans, color: C.text, flex: 1 }}>{group[0].description || "Sin descripción"}</span>
                    <span style={{ fontWeight: 800, fontSize: 14, color: C.red, fontFamily: fontSans }}>{fmt(group[0].amount)}</span>
                    {prop && <span style={{ fontSize: 11, background: (prop.color || C.accent) + "22", color: prop.color || C.accent, padding: "2px 8px", borderRadius: 12, fontWeight: 700, fontFamily: fontSans }}>{prop.name}</span>}
                  </div>
                  {group.map((e, ei) => {
                    const isAuto = isAutoGenerated(e);
                    const checked = !!dupSelected[e.id];
                    return (
                      <label key={e.id} style={{ display: "flex", alignItems: "center", gap: 12, padding: "10px 14px", background: checked ? C.redBg : (ei % 2 ? C.surfaceAlt : C.surface), cursor: "pointer", borderBottom: ei < group.length - 1 ? `1px solid ${C.border}` : "none", transition: "background 0.15s" }}>
                        <input type="checkbox" checked={checked} onChange={() => setDupSelected(s => ({ ...s, [e.id]: !s[e.id] }))} style={{ width: 16, height: 16, accentColor: C.red }} />
                        <div style={{ flex: 1 }}>
                          <div style={{ display: "flex", gap: 6, alignItems: "center", flexWrap: "wrap" }}>
                            <span style={{ fontSize: 12, fontFamily: fontSans, color: C.textMid }}>{fmtDateShort(e.date)}</span>
                            {e.supplier && <span style={{ fontSize: 11, color: C.textMuted, fontFamily: fontSans }}>· {e.supplier}</span>}
                            {e.invoiceNum && <span style={{ fontSize: 11, color: C.textMuted, fontFamily: fontSans }}>· Nº {e.invoiceNum}</span>}
                            {isAuto && <span style={{ fontSize: 10, background: C.blueBg, color: C.blue, padding: "1px 6px", borderRadius: 8, fontWeight: 700, fontFamily: fontSans }}>Auto-generado</span>}
                            {ei === 0 && <span style={{ fontSize: 10, background: C.greenBg, color: C.green, padding: "1px 6px", borderRadius: 8, fontWeight: 700, fontFamily: fontSans }}>Conservar</span>}
                          </div>
                        </div>
                        <Badge status={e.status} />
                      </label>
                    );
                  })}
                </div>
              );
            })}
          </div>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginTop: 18, paddingTop: 14, borderTop: `1px solid ${C.border}` }}>
            <span style={{ fontSize: 13, fontFamily: fontSans, color: C.textMuted }}>
              {Object.values(dupSelected).filter(Boolean).length} gasto{Object.values(dupSelected).filter(Boolean).length !== 1 ? "s" : ""} seleccionado{Object.values(dupSelected).filter(Boolean).length !== 1 ? "s" : ""} para eliminar
            </span>
            <div style={{ display: "flex", gap: 10 }}>
              <Btn variant="secondary" onClick={() => setModal(null)}>Cancelar</Btn>
              <Btn variant="danger" onClick={deleteDupes} style={{ opacity: Object.values(dupSelected).filter(Boolean).length === 0 ? 0.4 : 1 }}>
                🗑 Eliminar seleccionados
              </Btn>
            </div>
          </div>
        </Modal>
      )}

      {confirmDialog}
    </div>
  );
}

