          <input value={c.dni||""} onChange={e=>{ const arr=[...(form.cohabitants||[])]; arr[i]={...arr[i],dni:e.target.value}; setForm(p=>({...p,cohabitants:arr})); }} placeholder="DNI/NIE" style={{ ...inputSt,flex:1 }} />
