function mortMonthlyAmort(m) {
  const rate = (m.interestRate || 0) / 100 / 12;
  if (!rate || !m.outstanding) return { interest: 0, principal: m.monthlyPayment || 0 };
  const interest  = m.outstanding * rate;
  const principal = Math.max(0, (m.monthlyPayment || 0) - interest);
  return { interest, principal };
}

// Build forward amortization schedule starting from current outstanding
function buildAmortSchedule(m, months = 60) {
  const rate = (m.interestRate || 0) / 100 / 12;
  let balance = m.outstanding || 0;
  const payment = m.monthlyPayment || 0;
  const startDate = m.startDate ? new Date(m.startDate + "T12:00:00") : new Date();
  // Fast-forward to approximate current month count
  const now = new Date();
  const startMo = startDate.getFullYear() * 12 + startDate.getMonth();
  const nowMo   = now.getFullYear()       * 12 + now.getMonth();
  const elapsed = Math.max(0, nowMo - startMo);
  const rows = [];
  for (let i = 0; i < months; i++) {
    const interest  = rate ? balance * rate : 0;
    const principal = Math.max(0, payment - interest);
    const d = new Date(now.getFullYear(), now.getMonth() + i, 1);
    rows.push({
      n: elapsed + i + 1,
      date: d.toLocaleDateString("es-ES", { month: "short", year: "numeric" }),
      interest, principal,
      balance: Math.max(0, balance - principal),
    });
    balance = Math.max(0, balance - principal);
    if (balance <= 0) break;
  }
  return rows;
}

