function AiImporter({ data, setData, importType, onClose }) {
  // importType: "movimientos" | "hipotecas"
  const [step, setStep]           = useState("upload"); // upload | analyzing | preview | done
  const [fileText, setFileText]   = useState(null);
  const [fileName, setFileName]   = useState("");
  const [rows, setRows]           = useState([]);
  const [error, setError]         = useState(null);
  const [summary, setSummary]     = useState(null);
  const fileRef                   = useRef();

  const isMovimientos = importType === "movimientos";
  const title = isMovimientos ? "📥 Importar movimientos con IA" : "🏦 Importar hipotecas con IA";

  const loadFile = async file => {
    if (!file) return;
    setError(null);
    setFileName(file.name);
    const ext = file.name.split(".").pop().toLowerCase();
    try {
      if (ext === "csv" || ext === "txt") {
        const text = await file.text();
        setFileText(text);
      } else if (ext === "xlsx" || ext === "xls") {
        const ab = await file.arrayBuffer();
        const csv = await excelToText(ab);
        setFileText(csv);
      } else {
        setError("Formato no admitido. Sube un .csv, .txt, .xlsx o .xls");
      }
    } catch (err) { setError(err.message); }
  };

  const analyze = async () => {
    if (!fileText) return;
    setStep("analyzing");
    setError(null);
    try {
      const preview = simpleCsvText(fileText);
      const resp = await fetch("https://api.anthropic.com/v1/messages", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          model: "claude-sonnet-4-20250514",
          max_tokens: 8192,
          system: AI_PROMPTS[importType],
          messages: [{ role: "user", content: `Aquí está el contenido del fichero "${fileName}":\n\n${preview}` }],
        }),
      });
      const json = await resp.json();
      if (json.type === "error" || json.error) throw new Error(json.error?.message || JSON.stringify(json));
      if (json.stop_reason === "max_tokens") throw new Error("El archivo es demasiado grande. Exporta solo las filas del año actual e inténtalo de nuevo.");
      const raw = (json.content || []).map(b => b.text || "").join("").trim()
        .replace(/^```(?:json)?\s*/i, "").replace(/\s*```$/i, "").trim();
      let parsed;
      try { parsed = JSON.parse(raw); } catch(e) {
        // Try to salvage truncated JSON array
        const idx = raw.lastIndexOf("},");
        if (idx > 0) { try { parsed = JSON.parse(raw.slice(0, idx+1) + "]"); } catch { throw new Error("JSON truncado. El archivo tiene demasiadas filas. Prueba con un extracto más corto."); } }
        else throw new Error("No se pudo interpretar la respuesta de la IA. Intenta con un archivo más pequeño.");
      }
      const arr = Array.isArray(parsed) ? parsed : (parsed.rows || []);
      if (!arr.length) throw new Error("La IA no detectó ningún movimiento en el archivo.");
      setRows(arr);
      setStep("preview");
    } catch (err) {
      setError("Error al analizar con IA: " + (err.message || String(err)));
      setStep("upload");
    }
  };

  const doImport = () => {
    if (isMovimientos) {
      let newPay = 0, newExp = 0, skipped = 0;
      const addPayments = [], addExpenses = [];
      rows.forEach(r => {
        const prop = data.properties.find(p => p.name.toLowerCase().includes((r.propName||"").toLowerCase().split(" ")[0]) || String(p.id) === r.propName);
        const amt = parseFloat(r.amount);
        if (!r.date || isNaN(amt) || amt <= 0) { skipped++; return; }
        if ((r.type||"gasto").toLowerCase().includes("ingreso") || (r.type||"").toLowerCase().includes("cobro")) {
          addPayments.push({ id: Date.now() + Math.random(), propertyId: prop?.id||null, tenantId:null, amount:amt, date:r.date, status:r.status||"paid", concept:r.concept||"Ingreso importado", receiptNum:"IA-"+String(Date.now()).slice(-4) });
          newPay++;
        } else {
          addExpenses.push({ id: Date.now() + Math.random(), propertyId: prop?.id||null, amount:amt, date:r.date, status:r.status||"paid", description:r.concept||"Gasto importado", category:r.category||"Otro", supplier:r.supplier||"", deductible:true, paymentMethod:"Transferencia", supplierNif:"", invoiceNum:"", notes:"Importado IA" });
          newExp++;
        }
      });
      setData(d => ({ ...d, payments:[...d.payments,...addPayments], expenses:[...d.expenses,...addExpenses] }));
      setSummary({ newPay, newExp, skipped });
    } else {
      let added = 0, skipped = 0;
      const toAdd = [];
      rows.forEach(r => {
        const prop = data.properties.find(p => p.name.toLowerCase().includes((r.propName||"").toLowerCase().split(" ")[0]) || String(p.id) === r.propName);
        const oa = parseFloat(r.originalAmount), mp = parseFloat(r.monthlyPayment);
        if (!r.bank || isNaN(oa) || isNaN(mp)) { skipped++; return; }
        toAdd.push({ id:Date.now()+Math.random(), propertyId:prop?.id||null, bank:r.bank, originalAmount:oa, outstanding:parseFloat(r.outstanding)||oa, monthlyPayment:mp, interestRate:parseFloat(r.interestRate)||0, rateType:(r.rateType||"variable").toLowerCase().includes("fij")||(r.rateType||"").toLowerCase().includes("fix")?"fixed":"variable", startDate:r.startDate||null, endDate:r.endDate||null, euribor:r.euribor?parseFloat(r.euribor):null, spread:r.spread?parseFloat(r.spread):null });
        added++;
      });
      setData(d => ({ ...d, mortgages:[...d.mortgages,...toAdd] }));
      setSummary({ added, skipped });
    }
    setStep("done");
  };

  const typeChip = r => {
    const t = (r.type||"gasto").toLowerCase();
    return t.includes("ingreso")||t.includes("cobro")
      ? <span style={{ color:C.green, fontWeight:700, fontSize:11, background:C.greenBg, padding:"2px 8px", borderRadius:10 }}>↑ Ingreso</span>
      : <span style={{ color:C.red,   fontWeight:700, fontSize:11, background:C.redBg,   padding:"2px 8px", borderRadius:10 }}>↓ Gasto</span>;
  };

  const propChip = propName => {
    const prop = data.properties.find(p => p.name.toLowerCase().includes((propName||"").toLowerCase().split(" ")[0]));
    return prop
      ? <span style={{ background:(prop.color||C.accent)+"22", color:prop.color||C.accent, padding:"2px 8px", borderRadius:10, fontSize:11, fontWeight:700, fontFamily:fontSans }}>{prop.name}</span>
      : <span style={{ color:propName?C.amber:C.textMuted, fontSize:11, fontFamily:fontSans }}>⚠ {propName||"—"}</span>;
  };

  return (
    <Modal title={title} onClose={onClose} extraWide>

      {/* ── UPLOAD ─────────────────────────────────────────────────────────── */}
      {step === "upload" && (
        <div>
          <div style={{ background:C.purpleBg, border:`1px solid ${C.purple}22`, borderRadius:10, padding:"12px 16px", marginBottom:18, fontSize:13, fontFamily:fontSans, color:C.purple }}>
            <strong>✨ Importación inteligente:</strong> sube tu CSV o Excel tal como lo tienes. La IA detecta automáticamente las columnas y extrae los datos.
          </div>

          <div
            onClick={() => fileRef.current.click()}
            onDragOver={e => e.preventDefault()}
            onDrop={e => { e.preventDefault(); loadFile(e.dataTransfer.files[0]); }}
            style={{ border:`2px dashed ${fileText?C.accent:C.border}`, borderRadius:14, padding: fileText ? 16 : 32, cursor:"pointer", background:fileText?C.accentLight:C.surfaceAlt, textAlign:"center", transition:"all 0.2s", marginBottom:14, position:"relative" }}
          >
            {fileText ? (
              <div>
                <div style={{ display:"flex", alignItems:"center", gap:14, justifyContent:"center", padding:"8px 0" }}>
                  <span style={{ fontSize:40 }}>{fileName.endsWith(".pdf") ? "📄" : "📊"}</span>
                  <div style={{ textAlign:"left" }}>
                    <div style={{ fontWeight:700, fontSize:15, fontFamily:fontSans }}>{fileName}</div>
                    <div style={{ fontSize:12, color:C.textMuted, fontFamily:fontSans, marginTop:3 }}>
                      {fileText.split("\n").length} filas detectadas · Listo para analizar
                    </div>
                  </div>
                </div>
                <button onClick={e=>{e.stopPropagation();setFileText(null);setFileName("");}} style={{ position:"absolute",top:10,right:10,background:"rgba(0,0,0,0.5)",color:"#fff",border:"none",borderRadius:"50%",width:26,height:26,cursor:"pointer",fontSize:14 }}>×</button>
              </div>
            ) : (
              <div>
                <div style={{ fontSize:48, marginBottom:12 }}>📂</div>
                <div style={{ fontWeight:700, fontSize:16, fontFamily:fontSans, color:C.text, marginBottom:6 }}>Arrastra o haz clic para subir</div>
                <div style={{ fontSize:13, color:C.textMuted, fontFamily:fontSans }}>CSV (.csv, .txt) · Excel (.xlsx, .xls)</div>
              </div>
            )}
          </div>

          <input ref={fileRef} type="file" accept=".csv,.txt,.xlsx,.xls" onChange={e=>loadFile(e.target.files[0])} style={{ display:"none" }} />

          {/* Raw preview */}
          {fileText && (
            <div style={{ background:C.surfaceAlt, borderRadius:8, padding:"10px 12px", marginBottom:14, maxHeight:120, overflowY:"auto", border:`1px solid ${C.border}` }}>
              <div style={{ fontSize:10, color:C.textMuted, fontFamily:fontSans, fontWeight:700, marginBottom:4 }}>VISTA PREVIA DEL ARCHIVO</div>
              <pre style={{ fontSize:11, fontFamily:"monospace", color:C.textMid, margin:0, whiteSpace:"pre-wrap", wordBreak:"break-all" }}>
                {fileText.split("\n").slice(0,8).join("\n")}{fileText.split("\n").length>8?"\n...":""}
              </pre>
            </div>
          )}

          {error && <div style={{ background:C.redBg, color:C.red, padding:"10px 14px", borderRadius:8, fontSize:13, fontFamily:fontSans, marginBottom:12 }}>⚠ {error}</div>}

          <div style={{ display:"flex", gap:10, justifyContent:"flex-end" }}>
            <Btn variant="secondary" onClick={onClose}>Cancelar</Btn>
            <Btn disabled={!fileText} style={{ opacity:fileText?1:0.4 }} onClick={analyze}>✨ Analizar con IA</Btn>
          </div>
        </div>
      )}

      {/* ── ANALYZING ──────────────────────────────────────────────────────── */}
      {step === "analyzing" && (
        <div style={{ textAlign:"center", padding:"40px 0 28px" }}>
          <div style={{ fontSize:56, marginBottom:16, animation:"spin 1.5s linear infinite", display:"inline-block" }}>✨</div>
          <div style={{ fontWeight:700, fontSize:17, fontFamily:fontSans, color:C.text, marginBottom:8 }}>
            La IA está interpretando tu {isMovimientos?"archivo de movimientos":"archivo de hipotecas"}
          </div>
          <div style={{ fontSize:13, color:C.textMuted, fontFamily:fontSans }}>
            Detectando columnas, fechas, importes{isMovimientos?", tipo de movimiento y piso...":", bancos y condiciones..."}
          </div>
          <style>{`@keyframes spin{from{transform:rotate(0)}to{transform:rotate(360deg)}}`}</style>
        </div>
      )}

      {/* ── PREVIEW ────────────────────────────────────────────────────────── */}
      {step === "preview" && (
        <div>
          <div style={{ background:C.greenBg, border:`1px solid ${C.green}33`, borderRadius:10, padding:"10px 16px", marginBottom:14, fontSize:13, fontFamily:fontSans, color:C.green }}>
            <strong>✨ La IA detectó {rows.length} {isMovimientos?"movimientos":"hipotecas"}.</strong> Revisa los datos antes de importar. Las filas con ⚠ no encontraron el piso en tu lista — se importarán sin asignar piso.
          </div>

          <div style={{ overflowX:"auto", maxHeight:380, overflowY:"auto", border:`1px solid ${C.border}`, borderRadius:10, marginBottom:16 }}>
            {isMovimientos ? (
              <table style={{ width:"100%", borderCollapse:"collapse", minWidth:680 }}>
                <TH cols={["Fecha","Tipo","Concepto","Piso","Importe","Estado","Categoría"]} />
                <tbody>
                  {rows.map((r,i) => (
                    <tr key={i} style={{ borderBottom:`1px solid ${C.border}`, background:i%2?C.surfaceAlt:C.surface }}>
                      <td style={{ padding:"8px 12px", fontSize:12, fontFamily:fontSans, whiteSpace:"nowrap" }}>{r.date||"—"}</td>
                      <td style={{ padding:"8px 12px" }}>{typeChip(r)}</td>
                      <td style={{ padding:"8px 12px", fontSize:12, fontFamily:fontSans, maxWidth:200 }}><div style={{ overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap" }}>{r.concept||"—"}</div></td>
                      <td style={{ padding:"8px 12px" }}>{propChip(r.propName)}</td>
                      <td style={{ padding:"8px 12px", fontSize:13, fontWeight:700, fontFamily:fontSans, color:(r.type||"gasto").toLowerCase().includes("ingreso")?C.green:C.red }}>{fmt(parseFloat(r.amount)||0)}</td>
                      <td style={{ padding:"8px 12px" }}><Badge status={r.status||"paid"} /></td>
                      <td style={{ padding:"8px 12px", fontSize:11, color:C.textMid, fontFamily:fontSans }}>{r.category||"—"}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            ) : (
              <div style={{ overflowX:"auto", overflowY:"auto", maxHeight:480, border:`1px solid ${C.border}`, borderRadius:10 }}>
              <table style={{ width:"100%", borderCollapse:"collapse", minWidth:600 }}>
                <TH cols={["Banco","Piso","Importe original","Pendiente","Cuota/mes","Interés","Tipo"]} />
                <tbody>
                  {rows.map((r,i) => (
                    <tr key={i} style={{ borderBottom:`1px solid ${C.border}`, background:i%2?C.surfaceAlt:C.surface }}>
                      <td style={{ padding:"8px 12px", fontSize:13, fontWeight:600, fontFamily:fontSans }}>{r.bank||"—"}</td>
                      <td style={{ padding:"8px 12px" }}>{propChip(r.propName)}</td>
                      <td style={{ padding:"8px 12px", fontSize:13, fontFamily:fontSans }}>{fmt(parseFloat(r.originalAmount)||0)}</td>
                      <td style={{ padding:"8px 12px", fontSize:13, fontFamily:fontSans, color:C.red }}>{fmt(parseFloat(r.outstanding)||0)}</td>
                      <td style={{ padding:"8px 12px", fontSize:13, fontWeight:700, fontFamily:fontSans }}>{fmt(parseFloat(r.monthlyPayment)||0)}</td>
                      <td style={{ padding:"8px 12px", fontSize:12, fontFamily:fontSans }}>{r.interestRate}%</td>
                      <td style={{ padding:"8px 12px" }}><Badge status={(r.rateType||"variable").toLowerCase().includes("fij")||(r.rateType||"").toLowerCase().includes("fix")?"fixed":"variable"} /></td>
                    </tr>
                  ))}
                </tbody>
              </table>
              </div>
            )}
          </div>

          {error && <div style={{ background:C.redBg, color:C.red, padding:"10px 14px", borderRadius:8, fontSize:13, fontFamily:fontSans, marginBottom:12 }}>⚠ {error}</div>}

          <div style={{ display:"flex", gap:10, justifyContent:"flex-end" }}>
            <Btn variant="secondary" onClick={() => setStep("upload")}>← Volver</Btn>
            <Btn onClick={doImport}>✓ Confirmar e importar {rows.length} {isMovimientos?"movimientos":"hipotecas"}</Btn>
          </div>
        </div>
      )}

      {/* ── DONE ───────────────────────────────────────────────────────────── */}
      {step === "done" && (
        <div style={{ textAlign:"center", padding:"32px 0" }}>
          <div style={{ fontSize:56, marginBottom:16 }}>✅</div>
          <div style={{ fontWeight:800, fontSize:20, fontFamily:font, marginBottom:16 }}>Importación completada</div>
          {isMovimientos ? (
            <div style={{ display:"flex", gap:14, justifyContent:"center", marginBottom:20, flexWrap:"wrap" }}>
              {summary.newPay > 0  && <div style={{ background:C.greenBg, borderRadius:10, padding:"10px 20px" }}><div style={{ fontSize:24, fontWeight:800, color:C.green, fontFamily:fontSans }}>{summary.newPay}</div><div style={{ fontSize:11, color:C.textMuted, fontFamily:fontSans }}>ingresos</div></div>}
              {summary.newExp > 0  && <div style={{ background:C.redBg,   borderRadius:10, padding:"10px 20px" }}><div style={{ fontSize:24, fontWeight:800, color:C.red,   fontFamily:fontSans }}>{summary.newExp}</div><div style={{ fontSize:11, color:C.textMuted, fontFamily:fontSans }}>gastos</div></div>}
              {summary.skipped > 0 && <div style={{ background:C.amberBg, borderRadius:10, padding:"10px 20px" }}><div style={{ fontSize:24, fontWeight:800, color:C.amber, fontFamily:fontSans }}>{summary.skipped}</div><div style={{ fontSize:11, color:C.textMuted, fontFamily:fontSans }}>omitidos</div></div>}
            </div>
          ) : (
            <div style={{ display:"flex", gap:14, justifyContent:"center", marginBottom:20 }}>
              {summary.added   > 0 && <div style={{ background:C.greenBg, borderRadius:10, padding:"10px 20px" }}><div style={{ fontSize:24, fontWeight:800, color:C.green, fontFamily:fontSans }}>{summary.added}</div><div style={{ fontSize:11, color:C.textMuted, fontFamily:fontSans }}>hipotecas añadidas</div></div>}
              {summary.skipped > 0 && <div style={{ background:C.amberBg, borderRadius:10, padding:"10px 20px" }}><div style={{ fontSize:24, fontWeight:800, color:C.amber, fontFamily:fontSans }}>{summary.skipped}</div><div style={{ fontSize:11, color:C.textMuted, fontFamily:fontSans }}>omitidas</div></div>}
            </div>
          )}
          <Btn onClick={onClose}>Cerrar</Btn>
        </div>
      )}
    </Modal>
  );
}


// ═══════════════════════════════════════════════════════════════════════════════
// MOVIMIENTOS PAGE
// ═══════════════════════════════════════════════════════════════════════════════
function Movimientos({ data, setData }) {
  const [propFilter, setPropFilter] = useState("all");
  const [typeFilter, setTypeFilter] = useState("all"); // all | ingreso | gasto
  const [statusFilter, setStatusFilter] = useState("all");
  const [search, setSearch] = useState("");
  const [dateFrom, setDateFrom] = useState("");
  const [dateTo, setDateTo] = useState("");
  const [modal, setModal] = useState(null); // null | "aiMov" | "aiHip"

  // Aggregate all movements
  const allMovements = [
    ...data.payments.map(p => {
      const prop = data.properties.find(x => x.id === p.propertyId);
      const tenant = data.tenants.find(x => x.id === p.tenantId);
      return { id: "pay-" + p.id, rawId: p.id, source: "payment", date: p.date, concept: p.concept, amount: p.amount, type: "ingreso", propertyId: p.propertyId, propName: prop?.name || "—", propColor: prop?.color || C.accent, status: p.status, detail: tenant?.name?.split(" ").slice(0,2).join(" ") || "", receiptNum: p.receiptNum };
    }),
    ...data.expenses.map(e => {
      const prop = data.properties.find(x => x.id === e.propertyId);
      return { id: "exp-" + e.id, rawId: e.id, source: "expense", date: e.date, concept: e.description, amount: e.amount, type: "gasto", propertyId: e.propertyId, propName: prop?.name || "—", propColor: prop?.color || C.accent, status: e.status, detail: e.category, supplier: e.supplier || "", deductible: e.deductible };
    }),
  ].sort((a, b) => new Date(b.date) - new Date(a.date));

  const filtered = allMovements.filter(m => {
    if (propFilter !== "all" && m.propertyId !== +propFilter) return false;
    if (typeFilter !== "all" && m.type !== typeFilter) return false;
    if (statusFilter !== "all" && m.status !== statusFilter) return false;
    if (dateFrom && m.date < dateFrom) return false;
    if (dateTo && m.date > dateTo) return false;
    if (search) {
      const s = search.toLowerCase();
      if (!m.concept?.toLowerCase().includes(s) && !m.propName?.toLowerCase().includes(s) && !m.detail?.toLowerCase().includes(s) && !m.supplier?.toLowerCase().includes(s)) return false;
    }
    return true;
  });

  const totalIngresos = filtered.filter(m => m.type === "ingreso" && m.status === "paid").reduce((s, m) => s + m.amount, 0);
  const totalGastos   = filtered.filter(m => m.type === "gasto"   && m.status === "paid").reduce((s, m) => s + m.amount, 0);
  const balance       = totalIngresos - totalGastos;

  const exportCsv = () => {
    const header = "fecha;concepto;tipo;importe;piso;estado;detalle";
    const lines = filtered.map(m => [m.date, `"${m.concept}"`, m.type, m.amount.toFixed(2), `"${m.propName}"`, m.status, `"${m.detail}"`].join(";"));
    const csv = [header, ...lines].join("\n");
    const blob = new Blob([csv], { type: "text/csv;charset=utf-8;" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a"); a.href = url; a.download = "movimientos.csv"; a.click();
    URL.revokeObjectURL(url);
  };

  return (
    <div>
      <SH title="Movimientos"
        action={
          <div style={{ display: "flex", gap: 8, flexWrap: "wrap" }}>
            <Btn variant="secondary" onClick={exportCsv}>⬇ Exportar CSV</Btn>
            <Btn variant="ghost" onClick={() => setModal("aiHip")}>🏦 Importar hipotecas</Btn>
            <Btn onClick={() => setModal("aiMov")}>📥 Importar movimientos</Btn>
          </div>
        }
      />

      {/* KPI strip */}
      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(170px,1fr))", gap: 13, marginBottom: 22 }}>
        <div style={{ background: C.greenBg, borderRadius: 12, padding: "16px 18px", border: `1px solid ${C.green}33` }}>
          <div style={{ fontSize: 11, color: C.green, fontFamily: fontSans, fontWeight: 700, textTransform: "uppercase", marginBottom: 4 }}>↑ Ingresos (cobrado)</div>
          <div style={{ fontSize: 22, fontWeight: 800, fontFamily: fontSans, color: C.green }}>{fmt(totalIngresos)}</div>
        </div>
        <div style={{ background: C.redBg, borderRadius: 12, padding: "16px 18px", border: `1px solid ${C.red}33` }}>
          <div style={{ fontSize: 11, color: C.red, fontFamily: fontSans, fontWeight: 700, textTransform: "uppercase", marginBottom: 4 }}>↓ Gastos (pagado)</div>
          <div style={{ fontSize: 22, fontWeight: 800, fontFamily: fontSans, color: C.red }}>{fmt(totalGastos)}</div>
        </div>
        <div style={{ background: balance >= 0 ? C.greenBg : C.redBg, borderRadius: 12, padding: "16px 18px", border: `1px solid ${balance >= 0 ? C.green : C.red}33` }}>
          <div style={{ fontSize: 11, color: balance >= 0 ? C.green : C.red, fontFamily: fontSans, fontWeight: 700, textTransform: "uppercase", marginBottom: 4 }}>Balance neto</div>
          <div style={{ fontSize: 22, fontWeight: 800, fontFamily: fontSans, color: balance >= 0 ? C.green : C.red }}>{balance >= 0 ? "+" : ""}{fmt(balance)}</div>
        </div>
        <div style={{ background: C.surface, borderRadius: 12, padding: "16px 18px", border: `1px solid ${C.border}` }}>
          <div style={{ fontSize: 11, color: C.textMuted, fontFamily: fontSans, fontWeight: 700, textTransform: "uppercase", marginBottom: 4 }}>Movimientos</div>
          <div style={{ fontSize: 22, fontWeight: 800, fontFamily: fontSans, color: C.text }}>{filtered.length}</div>
        </div>
        {data.properties.filter(p => propFilter === "all" || p.id === +propFilter).map(p => {
          const inc = filtered.filter(m => m.propertyId === p.id && m.type === "ingreso" && m.status === "paid").reduce((s, m) => s + m.amount, 0);
          const exp = filtered.filter(m => m.propertyId === p.id && m.type === "gasto" && m.status === "paid").reduce((s, m) => s + m.amount, 0);
          return (
            <div key={p.id} style={{ background: C.surface, borderRadius: 12, padding: "16px 18px", borderLeft: `4px solid ${p.color}`, border: `1px solid ${C.border}`, borderLeftWidth: 4, borderLeftColor: p.color }}>
              <div style={{ fontSize: 11, color: C.textMuted, fontFamily: fontSans, fontWeight: 700, textTransform: "uppercase", marginBottom: 4 }}>{p.name}</div>
              <div style={{ fontSize: 14, fontWeight: 800, fontFamily: fontSans, color: C.green }}>{fmt(inc)}</div>
              <div style={{ fontSize: 11, color: C.red, fontFamily: fontSans, marginTop: 1 }}>−{fmt(exp)} gastos</div>
            </div>
          );
        })}
      </div>

      {/* Filters */}
      <div style={{ display: "flex", gap: 8, marginBottom: 16, flexWrap: "wrap", alignItems: "center" }}>
        <input value={search} onChange={e => setSearch(e.target.value)} placeholder="🔍 Buscar concepto, piso..." style={{ ...inputSt, width: 210, padding: "7px 12px" }} />
        <select value={propFilter} onChange={e => setPropFilter(e.target.value)} style={{ ...inputSt, width: "auto", padding: "7px 12px" }}>
          <option value="all">Todos los pisos</option>
          {data.properties.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
        </select>
        <select value={typeFilter} onChange={e => setTypeFilter(e.target.value)} style={{ ...inputSt, width: "auto", padding: "7px 12px" }}>
          <option value="all">Ingresos y gastos</option>
          <option value="ingreso">Solo ingresos</option>
          <option value="gasto">Solo gastos</option>
        </select>
        <select value={statusFilter} onChange={e => setStatusFilter(e.target.value)} style={{ ...inputSt, width: "auto", padding: "7px 12px" }}>
          <option value="all">Todos los estados</option>
          <option value="paid">Pagado</option>
          <option value="pending">Pendiente</option>
          <option value="overdue">Vencido</option>
        </select>
        <input type="date" value={dateFrom} onChange={e => setDateFrom(e.target.value)} style={{ ...inputSt, width: "auto", padding: "7px 10px", fontSize: 12 }} title="Desde" />
        <span style={{ color: C.textMuted, fontSize: 12, fontFamily: fontSans }}>→</span>
        <input type="date" value={dateTo} onChange={e => setDateTo(e.target.value)} style={{ ...inputSt, width: "auto", padding: "7px 10px", fontSize: 12 }} title="Hasta" />
        {(search || propFilter !== "all" || typeFilter !== "all" || statusFilter !== "all" || dateFrom || dateTo) &&
          <button onClick={() => { setSearch(""); setPropFilter("all"); setTypeFilter("all"); setStatusFilter("all"); setDateFrom(""); setDateTo(""); }}
            style={{ padding: "7px 13px", borderRadius: 8, border: `1px solid ${C.border}`, background: C.bg, cursor: "pointer", fontSize: 12, fontFamily: fontSans, color: C.textMid }}>✕ Limpiar</button>}
      </div>

      {/* Table */}
      <Card>
        <div style={{ overflowX: "auto" }}>
          <table style={{ width: "100%", borderCollapse: "collapse", minWidth: 740 }}>
            <TH cols={["Fecha","Tipo","Concepto","Piso","Detalle","Importe","Estado",""]} />
            <tbody>
              {filtered.map((m, i) => (
                <tr key={m.id} style={{ borderBottom: `1px solid ${C.border}`, background: i % 2 ? C.surfaceAlt : C.surface }}>
                  <td style={{ padding: "10px 14px", fontSize: 12, color: C.textMuted, fontFamily: fontSans, whiteSpace: "nowrap" }}>{fmtDateShort(m.date)}</td>
                  <td style={{ padding: "10px 14px" }}>
                    {m.type === "ingreso"
                      ? <span style={{ background: C.greenBg, color: C.green, padding: "3px 9px", borderRadius: 20, fontSize: 11, fontWeight: 700, fontFamily: fontSans }}>↑ Ingreso</span>
                      : <span style={{ background: C.redBg, color: C.red, padding: "3px 9px", borderRadius: 20, fontSize: 11, fontWeight: 700, fontFamily: fontSans }}>↓ Gasto</span>}
                  </td>
                  <td style={{ padding: "10px 14px", maxWidth: 220 }}>
                    <div style={{ fontWeight: 600, fontSize: 13, fontFamily: fontSans, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{m.concept}</div>
                    {m.source === "expense" && m.supplier && <div style={{ fontSize: 11, color: C.textMuted, fontFamily: fontSans }}>{m.supplier}</div>}
                    {m.source === "payment" && m.receiptNum && <div style={{ fontSize: 10, color: C.textMuted, fontFamily: fontSans }}>{m.receiptNum}</div>}
                  </td>
                  <td style={{ padding: "10px 14px" }}>
                    <span style={{ background: m.propColor + "22", color: m.propColor, padding: "2px 9px", borderRadius: 10, fontSize: 11, fontWeight: 700, fontFamily: fontSans, whiteSpace: "nowrap" }}>{m.propName}</span>
                  </td>
                  <td style={{ padding: "10px 14px", fontSize: 12, color: C.textMid, fontFamily: fontSans }}>
                    {m.detail}
                    {m.source === "expense" && m.deductible && <span style={{ marginLeft: 6, fontSize: 10, background: C.greenBg, color: C.green, padding: "1px 5px", borderRadius: 8, fontWeight: 700 }}>DED</span>}
                  </td>
                  <td style={{ padding: "10px 14px", fontSize: 14, fontWeight: 800, fontFamily: fontSans, whiteSpace: "nowrap", color: m.type === "ingreso" ? C.green : C.red }}>
                    {m.type === "ingreso" ? "+" : "−"}{fmt(m.amount)}
                  </td>
                  <td style={{ padding: "10px 14px" }}><Badge status={m.status} /></td>
                  <td style={{ padding: "10px 14px" }}>
                    <span style={{ fontSize: 11, color: C.textMuted, fontFamily: fontSans, padding: "3px 7px", background: C.bg, borderRadius: 6 }}>
                      {m.source === "payment" ? "💶 Pago" : "🧾 Gasto"}
                    </span>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
        {filtered.length === 0 && <div style={{ padding: 40, textAlign: "center", color: C.textMuted, fontFamily: fontSans }}>Sin movimientos con este filtro</div>}
      </Card>

      {/* Per-property breakdown when not filtered */}
      {propFilter === "all" && (
        <div style={{ marginTop: 24 }}>
          <h3 style={{ fontFamily: font, fontSize: 18, fontWeight: 700, marginBottom: 14, color: C.text }}>Desglose por piso</h3>
          <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(260px, 1fr))", gap: 14 }}>
            {data.properties.map(p => {
              const mForProp = allMovements.filter(m => m.propertyId === p.id);
              const inc = mForProp.filter(m => m.type === "ingreso" && m.status === "paid").reduce((s,m) => s + m.amount, 0);
              const exp = mForProp.filter(m => m.type === "gasto"   && m.status === "paid").reduce((s,m) => s + m.amount, 0);
              const pend = mForProp.filter(m => m.status === "pending" || m.status === "overdue").reduce((s,m) => s + m.amount, 0);
              const net = inc - exp;
              return (
                <Card key={p.id} style={{ padding: "16px 18px", borderLeft: `4px solid ${p.color}` }}>
                  <div style={{ fontWeight: 700, fontSize: 15, fontFamily: font, marginBottom: 12 }}>{p.name}</div>
                  <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 8 }}>
                    {[["↑ Cobrado", fmt(inc), C.green, C.greenBg], ["↓ Gastado", fmt(exp), C.red, C.redBg], ["Balance", fmt(net), net>=0?C.green:C.red, net>=0?C.greenBg:C.redBg], pend>0&&["Pendiente", fmt(pend), C.amber, C.amberBg]].filter(Boolean).map(([l, v, color, bg]) => (
                      <div key={l} style={{ background: bg, borderRadius: 8, padding: "8px 10px" }}>
                        <div style={{ fontSize: 10, color: C.textMuted, fontFamily: fontSans, fontWeight: 700 }}>{l}</div>
                        <div style={{ fontSize: 14, fontWeight: 800, color, fontFamily: fontSans }}>{v}</div>
                      </div>
                    ))}
                  </div>
                </Card>
              );
            })}
          </div>
        </div>
      )}

      {/* CSV import modals */}
      {modal === "aiMov" && <AiImporter data={data} setData={setData} importType="movimientos" onClose={() => setModal(null)} />}
      {modal === "aiHip" && <AiImporter data={data} setData={setData} importType="hipotecas"   onClose={() => setModal(null)} />}
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════════════════════
// MORTGAGE AUTO-EXPENSE GENERATOR
// Generates a "Hipoteca cuota" expense on day 1 of each month for every mortgage,
// from its start date (or up to 24 months back) through today.
// Entries are flagged with autoMortgage:true so they can be identified.
// ═══════════════════════════════════════════════════════════════════════════════
function autoGenerateMortgageExpenses(data) {
  const now = new Date();
  const nowYM = now.getFullYear() * 12 + now.getMonth();
  const suppressed = new Set(data.suppressedAutoIds || []);

  let expenses = [...data.expenses];
  let changed = false;

  data.mortgages.forEach(m => {
    if (!m.monthlyPayment) return;
    const prop = data.properties.find(p => p.id === m.propertyId);

    // Determine range: from mortgage start (max 24 months back) to current month
    const startDate = m.startDate ? new Date(m.startDate + "T12:00:00") : new Date(now.getFullYear() - 2, 0, 1);
    const startYM = startDate.getFullYear() * 12 + startDate.getMonth();
    const fromYM = Math.max(startYM, nowYM - 23); // up to 24 months

    for (let ym = fromYM; ym <= nowYM; ym++) {
      const year  = Math.floor(ym / 12);
      const month = ym % 12; // 0-based
      const monthStr = `${year}-${String(month + 1).padStart(2, "0")}`;
      const dateStr  = `${monthStr}-01`;
      const monthLabel = new Date(year, month, 1).toLocaleDateString("es-ES", { month: "long", year: "numeric" });
      const autoId = `mort-${m.id}-${monthStr}`;

      // Skip if the user explicitly deleted this auto-expense
      if (suppressed.has(autoId)) continue;

      // Check if an auto entry already exists for this mortgage+month
      const exists = expenses.some(e =>
        e.autoMortgage === true &&
        e.mortgageId === m.id &&
        e.date?.startsWith(monthStr)
      );
      if (!exists) {
        expenses.push({
          id: autoId,
          propertyId: m.propertyId,
          amount: m.monthlyPayment,
          date: dateStr,
          category: "Hipoteca cuota",
          description: `Cuota hipoteca ${prop?.name || ""} — ${monthLabel}`,
          status: "paid",
          deductible: false,
          supplier: m.bank || "",
          supplierNif: "",
          invoiceNum: "",
          paymentMethod: "Domiciliación",
          notes: "Generado automáticamente",
          autoMortgage: true,
          mortgageId: m.id,
        });
        changed = true;
      }
    }
  });

  return changed ? { ...data, expenses } : data;
}

// ── AUTO-GENERATE INSURANCE PENDING EXPENSES ──────────────────────────────────
// ── ADVANCE INSURANCE NEXT PAYMENT DATE when expense is paid ─────────────────
function advanceInsuranceDate(ins) {
  if (!ins.nextPaymentDate) return ins;
  const freqMonths = { "Mensual": 1, "Trimestral": 3, "Semestral": 6, "Anual": 12 };
  const months = freqMonths[ins.paymentFrequency] || 12;
  const d = new Date(ins.nextPaymentDate + "T12:00:00");
  d.setMonth(d.getMonth() + months);
  const next = d.toISOString().split("T")[0];
  return { ...ins, nextPaymentDate: next };
}

// For each insurance with nextPaymentDate, ensure there's a pending expense.
// The expense is linked via autoInsurance:true + insuranceId.
// If the insurance is updated (new date/amount), the old pending one is replaced.
function autoGenerateInsuranceExpenses(data) {
  const insurances = data.insurances || [];
  const suppressed = new Set(data.suppressedAutoIds || []);
  let expenses = [...data.expenses];
  let changed = false;

  insurances.forEach(ins => {
    if (!ins.nextPaymentDate) return;
    const premium = ins.annualPremium || 0;
    if (!premium) return;

    const autoId = `ins-${ins.id}-${ins.nextPaymentDate}`;
    // Skip if the user explicitly deleted this auto-expense
    if (suppressed.has(autoId)) return;

    // Calculate per-payment amount based on frequency
    const freqMap = { "Mensual": 12, "Trimestral": 4, "Semestral": 2, "Anual": 1 };
    const divisor = freqMap[ins.paymentFrequency] || 1;
    const paymentAmount = premium / divisor;

    const existingIdx = expenses.findIndex(e => e.autoInsurance === true && e.insuranceId === ins.id && e.status === "pending");
    // Never create a new expense for a date that already has one (paid or pending)
    const alreadyExists = expenses.some(e => e.autoInsurance === true && e.insuranceId === ins.id && e.date === ins.nextPaymentDate);
    if (alreadyExists && existingIdx < 0) return;

    const newExpense = {
      id: existingIdx >= 0 ? expenses[existingIdx].id : `ins-${ins.id}-${ins.nextPaymentDate}`,
      propertyId: ins.propertyId,
      amount: paymentAmount,
      date: ins.nextPaymentDate,
      category: "Seguro",
      description: `Seguro ${ins.type} — ${ins.company || ""}`,
      status: "pending",
      deductible: true,
      supplier: ins.company || "",
      supplierNif: "",
      invoiceNum: ins.policyNumber || "",
      paymentMethod: "Domiciliación",
      notes: `Generado automáticamente desde seguros. Póliza: ${ins.policyNumber || "—"}`,
      autoInsurance: true,
      insuranceId: ins.id,
    };

    if (existingIdx >= 0) {
      // Update if date or amount changed
      const existing = expenses[existingIdx];
      if (existing.date !== ins.nextPaymentDate || existing.amount !== paymentAmount) {
        expenses[existingIdx] = newExpense;
        changed = true;
      }
    } else {
      expenses.push(newExpense);
      changed = true;
    }
  });

  // Remove pending insurance expenses for deleted insurances
  const insIds = new Set(insurances.map(i => i.id));
  const before = expenses.length;
  expenses = expenses.filter(e => !(e.autoInsurance === true && !insIds.has(e.insuranceId) && e.status === "pending"));
  if (expenses.length !== before) changed = true;

  return changed ? { ...data, expenses } : data;
}

// ── AUTO-GENERATE RECURRING EXPENSE NEXT OCCURRENCE ──────────────────────────
// For each expense with isRecurring:true and nextDueDate, if today >= nextDueDate - 7 days
// and there's no already-generated pending child for that date, create one.
function advanceRecurringExpenses(data) {
  const today = new Date();
  today.setHours(0,0,0,0);
  const suppressed = new Set(data.suppressedAutoIds || []);
  let expenses = [...data.expenses];
  let changed = false;

  const PERIOD_MONTHS = { "Mensual": 1, "Bimestral": 2, "Trimestral": 3, "Semestral": 6, "Anual": 12 };

  function addPeriod(dateStr, period) {
    const d = new Date(dateStr + "T12:00:00");
    const months = PERIOD_MONTHS[period] || 1;
    d.setMonth(d.getMonth() + months);
    return d.toISOString().split("T")[0];
  }

  // Work on a snapshot length to avoid infinite loops
  const len = expenses.length;
  for (let i = 0; i < len; i++) {
    const e = expenses[i];
    if (!e.isRecurring || !e.nextDueDate || e.status !== "paid") continue;
    // Don't generate from auto-generated children (prevent chain on children)
    if (e.autoRecurring) continue;

    const dueDate = new Date(e.nextDueDate + "T12:00:00");
    const triggerDate = new Date(dueDate);
    triggerDate.setDate(triggerDate.getDate() - 7); // 7 days before

    if (today < triggerDate) continue; // too early

    const autoId = `rec-${e.id}-${e.nextDueDate}`;
    // Skip if the user explicitly deleted this auto-expense
    if (suppressed.has(autoId)) continue;

    // Check if a pending child already exists for this parent+dueDate
    const alreadyExists = expenses.some(x =>
      x.autoRecurring === true &&
      x.recurringParentId === e.id &&
      x.date === e.nextDueDate &&
      x.status === "pending"
    );

    if (!alreadyExists) {
      expenses.push({
        id: autoId,
        propertyId: e.propertyId,
        amount: e.amount,
        date: e.nextDueDate,
        category: e.category,
        description: e.description,
        status: "pending",
        deductible: e.deductible || false,
        supplier: e.supplier || "",
        supplierNif: e.supplierNif || "",
        invoiceNum: "",
        paymentMethod: e.paymentMethod || "Transferencia",
        notes: `Recurrente generado automáticamente (${e.recurrencePeriod || "Mensual"})`,
        autoRecurring: true,
        recurringParentId: e.id,
        isRecurring: true,
        recurrencePeriod: e.recurrencePeriod,
        nextDueDate: addPeriod(e.nextDueDate, e.recurrencePeriod),
      });
      // Update parent's nextDueDate to next cycle
      expenses[i] = { ...e, nextDueDate: addPeriod(e.nextDueDate, e.recurrencePeriod) };
      changed = true;
    }
  }

  return changed ? { ...data, expenses } : data;
}

function Renta({ data }) {
  const currentYear = new Date().getFullYear();
  const allYears = [...new Set([
    ...data.payments.map(p=>p.date?.slice(0,4)),
    ...data.expenses.map(e=>e.date?.slice(0,4)),
  ].filter(Boolean))].sort((a,b)=>b-a);
  const [year, setYear] = useState(String(currentYear - 1) || allYears[0] || String(currentYear));
  const [propId, setPropId] = useState(data.properties[0]?.id || "");
  const [irpfTramo, setIrpfTramo] = useState(45);

  const prop = data.properties.find(p => p.id === +propId);
  const m    = prop ? data.mortgages.find(x => x.propertyId === prop.id) : null;

  // Ingresos de alquiler del año
  const incomeRows = data.payments
    .filter(p => p.propertyId === +propId && p.status === "paid" && p.date?.startsWith(year))
    .sort((a,b) => new Date(a.date)-new Date(b.date));
  const totalIncome = incomeRows.reduce((s,p) => s + p.amount, 0);

  // Gastos deducibles del año (excluye "Hipoteca cuota" ya que los intereses se calculan aparte)
  const expenseRows = data.expenses
    .filter(e => e.propertyId === +propId && e.deductible && e.status === "paid" && e.date?.startsWith(year) && e.category !== "Hipoteca cuota")
    .sort((a,b) => new Date(a.date)-new Date(b.date));
  const totalExpenses = expenseRows.reduce((s,e) => s + e.amount, 0);

  // Intereses hipoteca para el periodo alquilado del año
  // Usamos meses con ingresos como proxy de meses alquilados
  const monthsWithIncome = new Set(incomeRows.map(p => p.date?.slice(0,7)));
  const nMonthsRented = monthsWithIncome.size;
  const { interest: monthInterest } = m ? mortMonthlyAmort(m) : { interest: 0 };
  const annualInterest = monthInterest * nMonthsRented;

  // Amortización 3% sobre precio de compra (valor catastral deducible)
  const amort3pct = prop?.purchasePrice ? prop.purchasePrice * 0.03 : 0;

  const totalDeductible = totalExpenses + annualInterest + amort3pct;
  const baseImponible = totalIncome - totalDeductible;
  const baseConBonif = baseImponible * 0.5; // 50% bonificación vivienda habitual alquilada
  const cuotaIRPF = baseConBonif > 0 ? baseConBonif * (irpfTramo / 100) : 0;

  const selSt = { ...inputSt, width:"auto", padding:"7px 12px", fontSize:13 };

  const TaxRow = ({ label, value, color, bold, indent }) => (
    <tr style={{ borderBottom:`1px solid ${C.border}` }}>
      <td style={{ padding:"10px 14px", fontSize:13, fontFamily:fontSans, color:C.textMid, paddingLeft: indent ? 28 : 14 }}>{label}</td>
      <td style={{ padding:"10px 14px", fontSize:13, fontWeight:bold?800:500, fontFamily:fontSans, color:color||C.text, textAlign:"right", whiteSpace:"nowrap" }}>{value}</td>
    </tr>
  );

  return (
    <div>
      <SH title="Declaración de la renta" />

      {/* Controls */}
      <div style={{ display:"flex",gap:12,marginBottom:22,flexWrap:"wrap",alignItems:"center" }}>
        <select value={propId} onChange={e=>setPropId(e.target.value)} style={selSt}>
          {data.properties.map(p=><option key={p.id} value={p.id}>{p.name}</option>)}
        </select>
        <select value={year} onChange={e=>setYear(e.target.value)} style={selSt}>
          {allYears.map(y=><option key={y} value={y}>{y}</option>)}
          {!allYears.includes(String(currentYear))&&<option value={String(currentYear)}>{currentYear}</option>}
        </select>
        <div style={{ display:"flex",alignItems:"center",gap:8 }}>
          <span style={{ fontSize:13,fontFamily:fontSans,color:C.textMid,fontWeight:600 }}>Tramo IRPF:</span>
          <select value={irpfTramo} onChange={e=>setIrpfTramo(+e.target.value)} style={{ ...selSt }}>
            {[19,24,30,37,45,47].map(t=><option key={t} value={t}>{t}%</option>)}
          </select>
        </div>
      </div>

      {!prop ? <div style={{ textAlign:"center",padding:50,color:C.textMuted,fontFamily:fontSans }}>Selecciona un piso</div> : (
        <div style={{ display:"grid",gap:20 }}>

          {/* Result box */}
          <div style={{ background:C.text,borderRadius:16,padding:"22px 26px",display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(160px,1fr))",gap:20 }}>
            {[
              {l:"Ingresos alquiler",v:fmt(totalIncome),c:"#6ee7b7"},
              {l:"Gastos deducibles",v:fmt(totalDeductible),c:"#fca5a5"},
              {l:"Base imponible",v:fmt(baseImponible),c:baseImponible>=0?"#fbbf24":"#6ee7b7"},
              {l:"Base con bonif. 50%",v:fmt(baseConBonif),c:"#c4b5fd"},
              {l:`Cuota IRPF (${irpfTramo}%)`,v:fmt(cuotaIRPF),c:cuotaIRPF>0?"#fca5a5":"#6ee7b7"},
            ].map((x,i)=>(
              <div key={i}>
                <div style={{ fontSize:10,color:"rgba(255,255,255,0.4)",fontFamily:fontSans,fontWeight:700,textTransform:"uppercase",letterSpacing:"0.07em",marginBottom:4 }}>{x.l}</div>
                <div style={{ fontSize:22,fontWeight:800,color:x.c,fontFamily:fontSans }}>{x.v}</div>
              </div>
            ))}
          </div>

          <Card style={{ padding:0,overflow:"hidden" }}>
            <div style={{ padding:"14px 18px",borderBottom:`1px solid ${C.border}`,fontWeight:700,fontSize:15,fontFamily:font }}>📋 Detalle del cálculo — {prop.name} {year}</div>
            <div style={{ overflowX:"auto" }}>
              <table style={{ width:"100%",borderCollapse:"collapse" }}>
                <tbody>
                  {/* Ingresos */}
                  <tr style={{ background:C.greenBg }}><td colSpan={2} style={{ padding:"8px 14px",fontSize:11,fontWeight:800,color:C.green,fontFamily:fontSans,textTransform:"uppercase",letterSpacing:"0.06em" }}>Ingresos de alquiler</td></tr>
                  {incomeRows.length===0 && <TaxRow label="Sin pagos registrados" value="0 €" color={C.textMuted} indent />}
                  {incomeRows.map(p=>(
                    <TaxRow key={p.id} label={`${fmtDateShort(p.date)} · ${p.concept||"Alquiler"}`} value={fmt(p.amount)} color={C.green} indent />
                  ))}
                  <TaxRow label="TOTAL INGRESOS" value={fmt(totalIncome)} color={C.green} bold />

                  {/* Gastos deducibles */}
                  <tr style={{ background:C.redBg }}><td colSpan={2} style={{ padding:"8px 14px",fontSize:11,fontWeight:800,color:C.red,fontFamily:fontSans,textTransform:"uppercase",letterSpacing:"0.06em" }}>Gastos deducibles</td></tr>
                  {expenseRows.map(e=>(
                    <TaxRow key={e.id} label={`${fmtDateShort(e.date)} · ${e.description} (${e.category})`} value={`-${fmt(e.amount)}`} color={C.red} indent />
                  ))}
                  {annualInterest > 0 && <TaxRow label={`Intereses hipoteca ${m?.bank||""} (${nMonthsRented} meses alquilados × ${fmt(monthInterest)}/mes)`} value={`-${fmt(annualInterest)}`} color={C.amber} indent />}
                  {amort3pct > 0 && <TaxRow label={`Amortización inmueble 3% × precio compra ${fmt(prop.purchasePrice)}`} value={`-${fmt(amort3pct)}`} color={C.amber} indent />}
                  <TaxRow label="TOTAL GASTOS DEDUCIBLES" value={`-${fmt(totalDeductible)}`} color={C.red} bold />

                  {/* Cálculo final */}
                  <tr style={{ background:C.surfaceAlt }}><td colSpan={2} style={{ padding:"8px 14px",fontSize:11,fontWeight:800,color:C.textMid,fontFamily:fontSans,textTransform:"uppercase",letterSpacing:"0.06em" }}>Cálculo IRPF</td></tr>
                  <TaxRow label="Base imponible (ingresos − gastos)" value={fmt(baseImponible)} color={baseImponible>=0?C.amber:C.green} bold />
                  <TaxRow label="Reducción 50% (arrendamiento vivienda habitual)" value={`-${fmt(baseImponible*0.5)}`} color={C.purple} indent />
                  <TaxRow label="Base liquidable" value={fmt(baseConBonif)} bold />
                  <TaxRow label={`Tipo marginal IRPF (${irpfTramo}%)`} value={`× ${irpfTramo}%`} indent />
                  <tr style={{ background: cuotaIRPF>0?C.redBg:C.greenBg }}>
                    <td style={{ padding:"13px 14px",fontSize:15,fontWeight:800,fontFamily:fontSans,color:cuotaIRPF>0?C.red:C.green }}>💰 CUOTA IRPF ESTIMADA</td>
                    <td style={{ padding:"13px 14px",fontSize:18,fontWeight:800,fontFamily:fontSans,color:cuotaIRPF>0?C.red:C.green,textAlign:"right" }}>{fmt(cuotaIRPF)}</td>
                  </tr>
                </tbody>
              </table>
            </div>
          </Card>

          <Card style={{ padding:"13px 18px",background:C.amberBg,border:`1.5px solid #f6d28a` }}>
            <div style={{ fontSize:13,fontFamily:fontSans,color:C.amber }}>
              <strong>⚠ Aviso:</strong> Este cálculo es orientativo. La fórmula aplicada es: <em>(Ingresos − Gastos deducibles − 3% precio compra) × 50% × tramo IRPF</em>. Consulta siempre con tu asesor fiscal para la declaración oficial.
            </div>
          </Card>
        </div>
      )}
    </div>
  );
}

