        {(search||roleFilter!=="all"||propFilter!=="all")&&<button onClick={()=>{setSearch("");setRoleFilter("all");setPropFilter("all");}} style={{ padding:"7px 12px",borderRadius:8,border:`1px solid ${C.border}`,background:C.bg,cursor:"pointer",fontSize:12,fontFamily:fontSans,color:C.textMid }}>✕</button>}
