// INSURANCES PAGE
// ═══════════════════════════════════════════════════════════════════════════════
const INS_TYPES = ["Hogar","Impago de alquiler","Multirriesgo","Responsabilidad civil","Vida","Accidentes","Comunidad","Otro"];
const INS_PAYMENT_FREQ = ["Mensual","Trimestral","Semestral","Anual"];

function InsuranceScanner({ properties, onResult, onClose }) {
  const [stage, setStage] = useState("upload");
  const [fileInfo, setFileInfo] = useState(null);
  const [error, setError] = useState(null);
  const fileRef = useRef();
  const MIME_REMAP3 = { "image/jpg":"image/jpeg" };

  const loadFile = file => {
    if (!file) return;
    const isPdf = file.type==="application/pdf";
    const validImg = ["image/jpeg","image/png","image/webp","image/gif","image/jpg"].includes(file.type);
    if (!isPdf && !validImg) { setError("Formato no admitido."); return; }
    setError(null);
    const reader = new FileReader();
    reader.onload = e => {
      const dataUrl = e.target.result;
      setFileInfo({ dataUrl, base64:dataUrl.split(",")[1], mime:isPdf?"application/pdf":(MIME_REMAP3[file.type.toLowerCase()]||file.type), isPdf, name:file.name });
    };
    reader.readAsDataURL(file);
  };

  const scan = async () => {
    if (!fileInfo) return;
    setStage("scanning"); setError(null);
    try {
      const sys = `Eres un experto en seguros de inmuebles en España. Analiza el documento de seguro (póliza, certificado, recibo, etc.) y extrae todos los datos relevantes.
Responde ÚNICAMENTE con JSON válido, sin markdown ni texto adicional. Si un campo no aparece usa null.
{
  "company": "compañía aseguradora",
  "policyNumber": "número de póliza o null",
  "type": "uno de: Hogar,Impago de alquiler,Multirriesgo,Responsabilidad civil,Vida,Accidentes,Comunidad,Otro",
  "annualPremium": importe prima anual numérico o null,
  "amount": importe asegurado/capital garantizado numérico o null,
  "startDate": "fecha inicio vigencia YYYY-MM-DD o null",
  "endDate": "fecha fin vigencia / vencimiento YYYY-MM-DD o null",
  "nextPaymentDate": "fecha próximo pago YYYY-MM-DD o null",
  "paymentFrequency": "uno de: Mensual,Trimestral,Semestral,Anual",
  "coverages": ["cobertura 1","cobertura 2",...],
  "features": "características o condiciones especiales como texto libre o null",
  "insuranceAgent": "agente o mediador o null",
  "agentPhone": "teléfono del agente o null",
  "agentEmail": "email del agente o null",
  "franchise": importe franquicia numérico o null,
  "notes": "otras observaciones relevantes o null"
}`;
      const block = fileInfo.isPdf
        ? { type:"document", source:{ type:"base64", media_type:"application/pdf", data:fileInfo.base64 } }
        : { type:"image",    source:{ type:"base64", media_type:fileInfo.mime,     data:fileInfo.base64 } };
      const resp = await fetch("https://api.anthropic.com/v1/messages", {
        method:"POST", headers:{"Content-Type":"application/json"},
        body: JSON.stringify({ model:"claude-sonnet-4-20250514", max_tokens:1500, system:sys,
          messages:[{ role:"user", content:[block, { type:"text", text:"Extrae los datos del seguro. Solo JSON." }] }] })
      });
      const json = await resp.json();
      if (json.type==="error"||json.error) throw new Error(json.error?.message||JSON.stringify(json));
      const raw = (json.content||[]).map(b=>b.text||"").join("").trim().replace(/^```(?:json)?\s*/i,"").replace(/\s*```$/i,"").trim();
      onResult(JSON.parse(raw));
    } catch(err) {
      setError("No se pudo analizar: " + (err.message||String(err)));
      setStage("upload");
    }
  };

  if (stage==="scanning") return (
    <Modal title="Analizando póliza..." onClose={onClose}>
      <div style={{ textAlign:"center", padding:"32px 0 24px" }}>
        <div style={{ fontSize:52, marginBottom:16, animation:"spin 1.5s linear infinite", display:"inline-block" }}>✨</div>
        <div style={{ fontWeight:700, fontSize:16, fontFamily:fontSans, marginBottom:8 }}>Extrayendo datos del seguro</div>
        <div style={{ fontSize:13, color:C.textMuted, fontFamily:fontSans }}>Compañía, prima, vigencia, coberturas...</div>
        <style>{`@keyframes spin{from{transform:rotate(0)}to{transform:rotate(360deg)}}`}</style>
      </div>
    </Modal>
  );

  return (
    <Modal title="✨ Escanear póliza / recibo de seguro" onClose={onClose} wide>
      <div style={{ fontSize:13, color:C.textMid, fontFamily:fontSans, marginBottom:14 }}>
        Sube la <strong>póliza</strong>, recibo o certificado del seguro. La IA extraerá compañía, prima, vigencia, coberturas y más.
      </div>
      <div onDragOver={e=>e.preventDefault()} onDrop={e=>{e.preventDefault();loadFile(e.dataTransfer.files[0]);}}
        onClick={()=>!fileInfo&&fileRef.current.click()}
        style={{ border:`2px dashed ${fileInfo?C.accent:C.border}`, borderRadius:14, padding:fileInfo?16:28, cursor:fileInfo?"default":"pointer", background:fileInfo?C.accentLight:C.surfaceAlt, textAlign:"center", marginBottom:14, transition:"all 0.2s" }}>
        {fileInfo ? (
          <div style={{ position:"relative" }}>
            {fileInfo.isPdf
              ? <div style={{ display:"flex",alignItems:"center",gap:12,justifyContent:"center",padding:"6px 0" }}><span style={{ fontSize:40 }}>📄</span><div style={{ textAlign:"left" }}><div style={{ fontWeight:700,fontFamily:fontSans }}>{fileInfo.name}</div><div style={{ fontSize:12,color:C.textMuted,fontFamily:fontSans }}>PDF listo para analizar</div></div></div>
              : <img src={fileInfo.dataUrl} alt="" style={{ maxHeight:200,maxWidth:"100%",borderRadius:8,objectFit:"contain" }} />}
            <button onClick={e=>{e.stopPropagation();setFileInfo(null);}} style={{ position:"absolute",top:-4,right:-4,background:"rgba(0,0,0,0.55)",color:"#fff",border:"none",borderRadius:"50%",width:24,height:24,cursor:"pointer",fontSize:14 }}>×</button>
          </div>
        ) : (
          <div>
            <div style={{ fontSize:36, marginBottom:10 }}>🛡</div>
            <div style={{ fontWeight:700, fontFamily:fontSans, marginBottom:4 }}>Arrastra o haz clic para subir</div>
            <div style={{ fontSize:12, color:C.textMuted, fontFamily:fontSans }}>JPG, PNG, PDF — póliza, recibo, certificado de seguro</div>
          </div>
        )}
      </div>
      <input ref={fileRef} type="file" accept="image/*,application/pdf" onChange={e=>loadFile(e.target.files[0])} style={{ display:"none" }} />
      {error && <div style={{ background:C.redBg, color:C.red, borderRadius:8, padding:"10px 14px", fontSize:13, fontFamily:fontSans, marginBottom:12 }}>⚠ {error}</div>}
      <div style={{ display:"flex", gap:10, justifyContent:"flex-end" }}>
        <Btn variant="secondary" onClick={onClose}>Cancelar</Btn>
        <Btn variant="purple" onClick={scan} disabled={!fileInfo}>✨ Analizar con IA</Btn>
      </div>
    </Modal>
  );
}

function Insurances({ data, setData }) {
  const [modal, setModal]   = useState(null); // null | "add" | "edit" | "scan" | "view"
  const [confirm, confirmDialog] = useConfirm();
  const [form, setForm]     = useState({});
  const [hiFields, setHiFields] = useState([]);
  const [viewing, setViewing] = useState(null);
  const [propFilter, setPropFilter] = useState("all");
  const [typeFilter, setTypeFilter] = useState("all");
  const [coverageInput, setCoverageInput] = useState("");

  const fv = k => e => setForm(p=>({...p,[k]:e.target.type==="checkbox"?e.target.checked:e.target.value}));
  const hi = k => hiFields.includes(k);

  const defaultForm = () => ({
    company:"", policyNumber:"", type:"Hogar", propertyId:data.properties[0]?.id||"",
    annualPremium:"", amount:"", startDate:"", endDate:"",
    nextPaymentDate:"", paymentFrequency:"Anual",
    coverages:[], features:"", insuranceAgent:"", agentPhone:"", agentEmail:"",
    franchise:"", notes:"",
  });

  const save = () => {
    const ins = {
      ...form, id:form.id||Date.now(),
      propertyId: form.propertyId?+form.propertyId:null,
      annualPremium: form.annualPremium?+form.annualPremium:null,
      amount: form.amount?+form.amount:null,
      franchise: form.franchise?+form.franchise:null,
      coverages: form.coverages||[],
    };
    if (modal==="add"||modal==="scan") setData(d=>({...d,insurances:[...(d.insurances||[]),ins]}));
    else setData(d=>({...d,insurances:(d.insurances||[]).map(x=>x.id===ins.id?ins:x)}));
    setModal(null); setHiFields([]);
  };

  const del = async id => { if(await confirm("¿Eliminar este seguro?")) setData(d=>({...d,insurances:(d.insurances||[]).filter(x=>x.id!==id)})); };

  const onScanResult = parsed => {
    const base = { ...defaultForm() };
    const detected = [];
    Object.entries(parsed).forEach(([k,v])=>{
      if (v===null||v===undefined) return;
      if (k==="coverages") { if (Array.isArray(v)&&v.length>0) { base.coverages=v; detected.push(k); } return; }
      const s=String(v).trim();
      if (s!=="") { base[k]=s; detected.push(k); }
    });
    setForm(base); setHiFields(detected); setModal("scan");
  };

  const addCoverage = () => {
    const v = coverageInput.trim();
    if (!v) return;
    setForm(p=>({...p, coverages:[...(p.coverages||[]), v]}));
    setCoverageInput("");
  };
  const removeCoverage = i => setForm(p=>({...p, coverages:(p.coverages||[]).filter((_,idx)=>idx!==i)}));

  const allIns = data.insurances || [];
  const filtered = allIns.filter(ins=>{
    if (propFilter!=="all" && String(ins.propertyId)!==propFilter) return false;
    if (typeFilter!=="all" && ins.type!==typeFilter) return false;
    return true;
  });

  // Days until next payment
  const daysUntil = dateStr => {
    if (!dateStr) return null;
    const d = (new Date(dateStr+`T12:00:00`) - new Date()) / 86400000;
    return Math.round(d);
  };

  const TYPE_ICONS = { Hogar:"🏠", "Impago de alquiler":"🛡", Multirriesgo:"⚡", "Responsabilidad civil":"⚖", Vida:"❤", Accidentes:"🚑", Comunidad:"🏢", Otro:"📄" };
  const TYPE_COLOR = { Hogar:[C.blue,C.blueBg], "Impago de alquiler":[C.green,C.greenBg], Multirriesgo:[C.purple,C.purpleBg], "Responsabilidad civil":[C.amber,C.amberBg], Vida:[C.red,C.redBg], Otro:[C.textMid,"#f0ede8"] };
  const typeColor = t => TYPE_COLOR[t]||[C.textMid,"#f0ede8"];

  // Next payment urgency color
  const payUrgency = days => {
    if (days===null) return [C.textMuted, "#f0ede8"];
    if (days<0) return [C.red, C.redBg];
    if (days<=30) return [C.red, C.redBg];
    if (days<=90) return [C.amber, C.amberBg];
    return [C.green, C.greenBg];
  };

  const renderInsuranceForm = () => (
    <>
      {hiFields.length>0 && <div style={{ background:C.purpleBg, border:`1.5px solid ${C.purple}33`, borderRadius:10, padding:"9px 14px", marginBottom:14, fontSize:12, fontFamily:fontSans, color:C.purple, fontWeight:600 }}>✨ {hiFields.length} campos detectados por IA — resaltados en naranja</div>}

      <FRow>
        <Inp label="Compañía aseguradora" highlight={hi("company")} value={form.company||""} onChange={fv("company")} />
        <Inp label="Nº de póliza" highlight={hi("policyNumber")} value={form.policyNumber||""} onChange={fv("policyNumber")} />
      </FRow>
      <FRow>
        <Sel label="Tipología" value={form.type||"Hogar"} onChange={fv("type")}>
          {INS_TYPES.map(t=><option key={t} value={t}>{TYPE_ICONS[t]} {t}</option>)}
        </Sel>
        <Sel label="Piso asociado" value={form.propertyId||""} onChange={fv("propertyId")}>
          <option value="">— Sin piso —</option>
          {data.properties.map(p=><option key={p.id} value={p.id}>{p.name}</option>)}
        </Sel>
      </FRow>
      <FRow>
        <Inp label="Prima anual (€)" type="number" highlight={hi("annualPremium")} value={form.annualPremium||""} onChange={fv("annualPremium")} />
        <Inp label="Capital asegurado (€)" type="number" highlight={hi("amount")} value={form.amount||""} onChange={fv("amount")} />
      </FRow>
      <FRow>
        <Inp label="Inicio vigencia" type="date" highlight={hi("startDate")} value={form.startDate||""} onChange={fv("startDate")} />
        <Inp label="Fin vigencia / vencimiento" type="date" highlight={hi("endDate")} value={form.endDate||""} onChange={fv("endDate")} />
      </FRow>
      <FRow>
        <Inp label="Próximo pago" type="date" highlight={hi("nextPaymentDate")} value={form.nextPaymentDate||""} onChange={fv("nextPaymentDate")} />
        <Sel label="Periodicidad de pago" value={form.paymentFrequency||"Anual"} onChange={fv("paymentFrequency")}>
          {INS_PAYMENT_FREQ.map(f=><option key={f} value={f}>{f}</option>)}
        </Sel>
      </FRow>
      <Inp label="Franquicia (€)" type="number" highlight={hi("franchise")} value={form.franchise||""} onChange={fv("franchise")} />

      {/* Coverages */}
      <Field label="Principales coberturas">
        <div style={{ display:"flex", gap:8, marginBottom:8 }}>
          <input value={coverageInput} onChange={e=>setCoverageInput(e.target.value)} onKeyDown={e=>e.key==="Enter"&&(e.preventDefault(),addCoverage())} placeholder="Ej. Daños por agua, Robo, Incendio..." style={{ ...inputSt, flex:1 }} />
          <Btn variant="secondary" onClick={addCoverage} style={{ whiteSpace:"nowrap", flexShrink:0 }}>+ Añadir</Btn>
        </div>
        {(form.coverages||[]).length>0 && (
          <div style={{ display:"flex", flexWrap:"wrap", gap:7 }}>
            {(form.coverages||[]).map((cov,i)=>(
              <span key={i} style={{ background:C.greenBg, color:C.green, padding:"4px 10px", borderRadius:20, fontSize:12, fontFamily:fontSans, fontWeight:600, display:"flex", alignItems:"center", gap:5 }}>
                ✓ {cov}
                <button onClick={()=>removeCoverage(i)} style={{ background:"none", border:"none", cursor:"pointer", color:C.green, fontSize:14, lineHeight:1, padding:0 }}>×</button>
              </span>
            ))}
          </div>
        )}
      </Field>

      <Tex label="Características / condiciones especiales" value={form.features||""} onChange={fv("features")} style={{ minHeight:65 }} />

      <div style={{ height:1, background:C.border, margin:"6px 0 14px" }} />
      <div style={{ fontSize:11, fontWeight:700, color:C.textMuted, fontFamily:fontSans, textTransform:"uppercase", letterSpacing:"0.07em", marginBottom:10 }}>Datos del agente / mediador (opcional)</div>
      <FRow>
        <Inp label="Agente / mediador" highlight={hi("insuranceAgent")} value={form.insuranceAgent||""} onChange={fv("insuranceAgent")} />
        <Inp label="Teléfono agente" highlight={hi("agentPhone")} value={form.agentPhone||""} onChange={fv("agentPhone")} type="tel" />
      </FRow>
      <Inp label="Email agente" highlight={hi("agentEmail")} value={form.agentEmail||""} onChange={fv("agentEmail")} type="email" />
      <Tex label="Notas" value={form.notes||""} onChange={fv("notes")} style={{ minHeight:55 }} />
      <div style={{ display:"flex",gap:10,justifyContent:"flex-end",marginTop:8 }}>
        <Btn variant="secondary" onClick={()=>setModal(null)}>Cancelar</Btn>
        <Btn onClick={save}>Guardar seguro</Btn>
      </div>
    </>
  );

  // Total annual cost
  const totalPremium = allIns.reduce((s,i)=>s+(i.annualPremium||0),0);
  const expiring30   = allIns.filter(i=>{ const d=daysUntil(i.endDate); return d!==null&&d>=0&&d<=30; }).length;
  const pay30        = allIns.filter(i=>{ const d=daysUntil(i.nextPaymentDate); return d!==null&&d>=0&&d<=30; }).length;

  return (
    <div>
      <SH title="Seguros" action={
        <div style={{ display:"flex",gap:8,flexWrap:"wrap" }}>
          <Btn variant="purple" onClick={()=>setModal("scanUpload")}>✨ Escanear póliza</Btn>
          <Btn onClick={()=>{ setForm(defaultForm()); setHiFields([]); setCoverageInput(""); setModal("add"); }}>+ Añadir</Btn>
        </div>
      } />

      {/* Summary strip */}
      <div style={{ display:"flex",gap:10,marginBottom:18,flexWrap:"wrap" }}>
        {[
          ["Total seguros", allIns.length, C.text, C.bg],
          ["Prima anual total", fmt(totalPremium), C.red, C.redBg],
          expiring30>0 && ["Vencen pronto", expiring30, C.red, C.redBg],
          pay30>0      && ["Pagos en 30d",  pay30,       C.amber, C.amberBg],
        ].filter(Boolean).map(([l,v,col,bg])=>(
          <div key={l} style={{ background:bg, borderRadius:10, padding:"8px 16px" }}>
            <div style={{ fontSize:10, color:col, fontFamily:fontSans, fontWeight:700, textTransform:"uppercase", opacity:0.7, marginBottom:2 }}>{l}</div>
            <div style={{ fontWeight:800, fontSize:typeof v==="number"?20:16, color:col, fontFamily:fontSans }}>{v}</div>
          </div>
        ))}
      </div>

      {/* Filters */}
      <div style={{ display:"flex", gap:8, marginBottom:16, flexWrap:"wrap", alignItems:"center" }}>
        <select value={propFilter} onChange={e=>setPropFilter(e.target.value)} style={{ ...inputSt, width:"auto", padding:"7px 12px" }}>
          <option value="all">Todos los pisos</option>
          {data.properties.map(p=><option key={p.id} value={p.id}>{p.name}</option>)}
        </select>
        <select value={typeFilter} onChange={e=>setTypeFilter(e.target.value)} style={{ ...inputSt, width:"auto", padding:"7px 12px" }}>
          <option value="all">Todas las tipologías</option>
          {INS_TYPES.map(t=><option key={t} value={t}>{t}</option>)}
        </select>
      </div>

      {/* Cards */}
      <div style={{ display:"grid", gridTemplateColumns:"repeat(auto-fill,minmax(340px,1fr))", gap:16 }}>
        {filtered.map(ins=>{
          const prop   = data.properties.find(p=>p.id===ins.propertyId);
          const [tCol, tBg] = typeColor(ins.type);
          const daysNext = daysUntil(ins.nextPaymentDate);
          const daysEnd  = daysUntil(ins.endDate);
          const [pCol, pBg] = payUrgency(daysNext);
          const [eCol, eBg] = payUrgency(daysEnd);

          return (
            <Card key={ins.id} style={{ overflow:"hidden", cursor:"pointer" }} onClick={()=>setViewing(ins)}>
              {/* Header stripe */}
              <div style={{ background:`linear-gradient(135deg, ${tBg} 0%, ${tCol}18 100%)`, borderBottom:`1px solid ${tCol}22`, padding:"14px 18px 12px" }}>
                <div style={{ display:"flex", justifyContent:"space-between", alignItems:"flex-start" }}>
                  <div>
                    <div style={{ display:"flex", alignItems:"center", gap:8, marginBottom:4 }}>
                      <span style={{ fontSize:22 }}>{TYPE_ICONS[ins.type]||"📄"}</span>
                      <div style={{ fontWeight:800, fontSize:16, fontFamily:fontSans }}>{ins.company||"Sin compañía"}</div>
                    </div>
                    <div style={{ display:"flex", gap:6, flexWrap:"wrap" }}>
                      <span style={{ background:tBg, color:tCol, padding:"2px 9px", borderRadius:12, fontSize:11, fontWeight:700, fontFamily:fontSans, border:`1px solid ${tCol}33` }}>{ins.type}</span>
                      {prop && <span style={{ background:(prop.color||C.accent)+"22", color:prop.color||C.accent, padding:"2px 9px", borderRadius:12, fontSize:11, fontWeight:700, fontFamily:fontSans }}>🏠 {prop.name}</span>}
                    </div>
                  </div>
                  <div style={{ display:"flex",gap:5 }} onClick={e=>e.stopPropagation()}>
                    <button onClick={()=>{ setForm({...ins,coverages:ins.coverages||[]}); setHiFields([]); setCoverageInput(""); setModal("edit"); }} style={{ background:"rgba(255,255,255,0.7)",color:C.textMid,border:"none",borderRadius:6,padding:"4px 8px",cursor:"pointer",fontSize:12 }}>✏</button>
                    <button onClick={()=>del(ins.id)} style={{ background:C.redBg,color:C.red,border:"none",borderRadius:6,padding:"4px 8px",cursor:"pointer",fontSize:12 }}>🗑</button>
                  </div>
                </div>
              </div>

              {/* Body */}
              <div style={{ padding:"13px 18px" }}>
                {/* Key figures row */}
                <div style={{ display:"grid", gridTemplateColumns:"repeat(3,1fr)", gap:8, marginBottom:12 }}>
                  <div style={{ background:C.redBg, borderRadius:8, padding:"8px 10px", textAlign:"center" }}>
                    <div style={{ fontSize:10, color:C.red, fontFamily:fontSans, fontWeight:700, marginBottom:2 }}>Prima anual</div>
                    <div style={{ fontWeight:800, fontSize:14, color:C.red, fontFamily:fontSans }}>{ins.annualPremium?fmt(ins.annualPremium):"—"}</div>
                  </div>
                  {ins.amount && <div style={{ background:C.greenBg, borderRadius:8, padding:"8px 10px", textAlign:"center" }}>
                    <div style={{ fontSize:10, color:C.green, fontFamily:fontSans, fontWeight:700, marginBottom:2 }}>Capital</div>
                    <div style={{ fontWeight:800, fontSize:14, color:C.green, fontFamily:fontSans }}>{fmt(ins.amount)}</div>
                  </div>}
                  <div style={{ background:C.bg, borderRadius:8, padding:"8px 10px", textAlign:"center" }}>
                    <div style={{ fontSize:10, color:C.textMuted, fontFamily:fontSans, fontWeight:700, marginBottom:2 }}>Pago</div>
                    <div style={{ fontWeight:700, fontSize:12, color:C.textMid, fontFamily:fontSans }}>{ins.paymentFrequency||"—"}</div>
                  </div>
                </div>

                {/* Dates */}
                <div style={{ display:"flex", gap:8, flexWrap:"wrap", marginBottom:ins.coverages?.length>0?10:0 }}>
                  {ins.endDate && (
                    <div style={{ background:eBg, borderRadius:7, padding:"5px 10px", fontSize:11, fontFamily:fontSans, color:eCol, fontWeight:600 }}>
                      🗓 Vence: {fmtDateShort(ins.endDate)}{daysEnd!==null&&` (${daysEnd<0?"hace "+Math.abs(daysEnd):daysEnd} días${daysEnd<0?" — ⚠ VENCIDO":""})`}
                    </div>
                  )}
                  {ins.nextPaymentDate && (
                    <div style={{ background:pBg, borderRadius:7, padding:"5px 10px", fontSize:11, fontFamily:fontSans, color:pCol, fontWeight:600 }}>
                      💳 Pago: {fmtDateShort(ins.nextPaymentDate)}{daysNext!==null&&` (${daysNext<0?"vencido":daysNext+" días"})`}
                    </div>
                  )}
                </div>

                {/* Coverages chips */}
                {(ins.coverages||[]).length>0 && (
                  <div style={{ display:"flex", flexWrap:"wrap", gap:5, marginTop:8 }}>
                    {(ins.coverages||[]).slice(0,4).map((cov,i)=>(
                      <span key={i} style={{ background:C.greenBg, color:C.green, padding:"2px 8px", borderRadius:12, fontSize:10, fontFamily:fontSans, fontWeight:600 }}>✓ {cov}</span>
                    ))}
                    {(ins.coverages||[]).length>4 && <span style={{ background:C.bg, color:C.textMuted, padding:"2px 8px", borderRadius:12, fontSize:10, fontFamily:fontSans }}>+{ins.coverages.length-4} más</span>}
                  </div>
                )}

                {/* Policy number */}
                {ins.policyNumber && <div style={{ fontSize:11, color:C.textMuted, fontFamily:fontSans, marginTop:9 }}>Póliza: {ins.policyNumber}</div>}
              </div>
            </Card>
          );
        })}
      </div>
      {filtered.length===0 && <div style={{ textAlign:"center", padding:50, color:C.textMuted, background:C.surface, borderRadius:14, border:`1px solid ${C.border}`, fontFamily:fontSans }}>{allIns.length===0?"🛡 Sin seguros registrados. Escanea una póliza o añade uno manualmente.":"Sin resultados para este filtro."}</div>}

      {/* Detail view modal */}
      {viewing && (
        <Modal title={`${viewing.company||"Seguro"} — ${viewing.type||""}`} onClose={()=>setViewing(null)} wide>
          {(() => {
            const prop = data.properties.find(p=>p.id===viewing.propertyId);
            const [tCol, tBg] = typeColor(viewing.type);
            const daysNext = daysUntil(viewing.nextPaymentDate);
            const daysEnd  = daysUntil(viewing.endDate);
            const [pCol]   = payUrgency(daysNext);
            const [eCol, eBg] = payUrgency(daysEnd);
            return (
              <>
                {/* Header */}
                <div style={{ display:"flex", alignItems:"center", gap:12, marginBottom:20 }}>
                  <div style={{ width:56, height:56, borderRadius:14, background:tBg, display:"flex", alignItems:"center", justifyContent:"center", fontSize:26, border:`2px solid ${tCol}33`, flexShrink:0 }}>{TYPE_ICONS[viewing.type]||"📄"}</div>
                  <div>
                    <div style={{ fontWeight:800, fontSize:20, fontFamily:fontSans }}>{viewing.company}</div>
                    <div style={{ display:"flex", gap:6, marginTop:5, flexWrap:"wrap" }}>
                      <span style={{ background:tBg, color:tCol, padding:"3px 10px", borderRadius:12, fontSize:12, fontWeight:700, fontFamily:fontSans }}>{viewing.type}</span>
                      {prop && <span style={{ background:(prop.color||C.accent)+"22", color:prop.color||C.accent, padding:"3px 10px", borderRadius:12, fontSize:12, fontWeight:700, fontFamily:fontSans }}>🏠 {prop.name}</span>}
                      {viewing.policyNumber && <span style={{ background:C.bg, color:C.textMuted, padding:"3px 10px", borderRadius:12, fontSize:12, fontFamily:fontSans }}>Póliza: {viewing.policyNumber}</span>}
                    </div>
                  </div>
                </div>

                {/* Key data grid */}
                <div style={{ display:"grid", gridTemplateColumns:"repeat(auto-fill,minmax(140px,1fr))", gap:10, marginBottom:18 }}>
                  {[
                    viewing.annualPremium && ["💶 Prima anual", fmt(viewing.annualPremium), C.red, C.redBg],
                    viewing.amount        && ["🏦 Capital aseg.", fmt(viewing.amount), C.green, C.greenBg],
                    viewing.franchise     && ["✂ Franquicia", fmt(viewing.franchise), C.amber, C.amberBg],
                    viewing.paymentFrequency && ["🔁 Pago", viewing.paymentFrequency, C.blue, C.blueBg],
                    viewing.startDate     && ["📅 Inicio", fmtDateShort(viewing.startDate), C.textMid, C.bg],
                    viewing.endDate       && ["🗓 Vencimiento", fmtDateShort(viewing.endDate)+(daysEnd!==null?` (${daysEnd<0?"⚠ VENCIDO":daysEnd+" días"})` :""), daysEnd<30?eCol:C.textMid, daysEnd<30?eBg:C.bg],
                    viewing.nextPaymentDate && ["💳 Próx. pago", fmtDateShort(viewing.nextPaymentDate)+(daysNext!==null?` (${daysNext<0?"vencido":daysNext+" días"})` :""), pCol, C.bg],
                  ].filter(Boolean).map(([l,v,col,bg])=>(
                    <div key={l} style={{ background:bg||C.surfaceAlt, borderRadius:8, padding:"9px 12px" }}>
                      <div style={{ fontSize:10, color:C.textMuted, fontFamily:fontSans, fontWeight:700, textTransform:"uppercase", marginBottom:2 }}>{l}</div>
                      <div style={{ fontSize:13, fontWeight:700, fontFamily:fontSans, color:col||C.text }}>{v}</div>
                    </div>
                  ))}
                </div>

                {/* Coverages */}
                {(viewing.coverages||[]).length>0 && (
                  <div style={{ marginBottom:16 }}>
                    <div style={{ fontSize:11, fontWeight:700, color:C.textMuted, fontFamily:fontSans, textTransform:"uppercase", letterSpacing:"0.06em", marginBottom:8 }}>Principales coberturas</div>
                    <div style={{ display:"flex", flexWrap:"wrap", gap:7 }}>
                      {(viewing.coverages||[]).map((cov,i)=>(
                        <span key={i} style={{ background:C.greenBg, color:C.green, padding:"5px 12px", borderRadius:20, fontSize:12, fontFamily:fontSans, fontWeight:600 }}>✓ {cov}</span>
                      ))}
                    </div>
                  </div>
                )}

                {/* Features */}
                {viewing.features && (
                  <div style={{ background:C.surfaceAlt, borderRadius:8, padding:"10px 14px", marginBottom:14 }}>
                    <div style={{ fontSize:10, color:C.textMuted, fontFamily:fontSans, fontWeight:700, textTransform:"uppercase", marginBottom:5 }}>Características / condiciones</div>
                    <div style={{ fontSize:13, fontFamily:fontSans, color:C.text, whiteSpace:"pre-wrap" }}>{viewing.features}</div>
                  </div>
                )}

                {/* Agent */}
                {(viewing.insuranceAgent||viewing.agentPhone||viewing.agentEmail) && (
                  <div style={{ background:C.blueBg, border:`1px solid ${C.blue}22`, borderRadius:10, padding:"11px 14px", marginBottom:14 }}>
                    <div style={{ fontSize:10, color:C.blue, fontFamily:fontSans, fontWeight:700, textTransform:"uppercase", marginBottom:7 }}>Agente / Mediador</div>
                    <div style={{ display:"flex", gap:12, flexWrap:"wrap" }}>
                      {viewing.insuranceAgent && <div style={{ fontSize:13, fontFamily:fontSans, fontWeight:600 }}>👤 {viewing.insuranceAgent}</div>}
                      {viewing.agentPhone     && <div style={{ fontSize:13, fontFamily:fontSans, color:C.textMid }}>📱 {viewing.agentPhone}</div>}
                      {viewing.agentEmail     && <div style={{ fontSize:13, fontFamily:fontSans, color:C.blue }}>✉ {viewing.agentEmail}</div>}
                    </div>
                  </div>
                )}

                {viewing.notes && <div style={{ background:C.surfaceAlt, borderRadius:8, padding:"9px 14px", marginBottom:14, fontSize:13, fontFamily:fontSans, color:C.textMid, fontStyle:"italic" }}>📝 {viewing.notes}</div>}

                <div style={{ display:"flex", gap:10, justifyContent:"flex-end" }}>
                  <Btn variant="secondary" onClick={()=>setViewing(null)}>Cerrar</Btn>
                  <Btn onClick={()=>{ setForm({...viewing,coverages:viewing.coverages||[]}); setHiFields([]); setCoverageInput(""); setViewing(null); setModal("edit"); }}>✏ Editar</Btn>
                </div>
              </>
            );
          })()}
        </Modal>
      )}

      {/* Scan upload */}
      {modal==="scanUpload" && <InsuranceScanner properties={data.properties} onResult={onScanResult} onClose={()=>setModal(null)} />}

      {/* Add / Edit / Scan-result modals */}
      {(modal==="add"||modal==="edit"||(modal==="scan"&&hiFields.length>0)) && (
        <Modal title={modal==="edit"?"Editar seguro":modal==="scan"?"✨ Datos extraídos de la póliza":"Nuevo seguro"} onClose={()=>setModal(null)} wide>
          {renderInsuranceForm()}
        </Modal>
      )}
      {confirmDialog}
    </div>
  );
}


// ═══════════════════════════════════════════════════════════════════════════════
// APP SHELL
// ═══════════════════════════════════════════════════════════════════════════════
const TABS = [
  { id:"dashboard",    label:"Resumen",      icon:"◈" },
  { id:"properties",   label:"Pisos",         icon:"⌂" },
  { id:"tenants",      label:"Inquilinos",    icon:"◎" },
  { id:"payments",     label:"Pagos",         icon:"◷" },
  { id:"expenses",     label:"Gastos",        icon:"◉" },
  { id:"incidents",    label:"Incidencias",   icon:"◬" },
  { id:"mortgages",    label:"Hipotecas",     icon:"◰" },
  { id:"documents",    label:"Contratos",     icon:"◫" },
  { id:"insurances",   label:"Seguros",       icon:"🛡" },
  { id:"contacts",     label:"Contactos",     icon:"◌" },
  { id:"movimientos",  label:"Movimientos",   icon:"⇅" },
  { id:"finance",      label:"Financiero",    icon:"◑" },
  { id:"renta",        label:"Renta",         icon:"◐" },
  { id:"settings",     label:"Mis datos",     icon:"◍" },
];

export default function App() {
  const [tab, setTab]      = useState("dashboard");
  const [data, setDataRaw] = useState(INITIAL);
  const [loaded, setLoaded] = useState(false);
  const [menu, setMenu]    = useState(false);

  useEffect(() => {
    loadFromStorage().then(s => {
      const base = s || INITIAL;
      if (!Array.isArray(base.contacts))   base.contacts   = [];
      if (!Array.isArray(base.insurances)) base.insurances = [];
      let updated = autoGenerateMortgageExpenses(base);
      updated = autoGenerateInsuranceExpenses(updated);
      updated = advanceRecurringExpenses(updated);
      setDataRaw(updated);
      if (updated !== base) saveToStorage(updated);
      setLoaded(true);
    });
  }, []);

  // Re-run auto-generators separately to avoid cascade re-triggers
  const mortgagesKey  = JSON.stringify(data.mortgages.map(m => m.id + m.monthlyPayment));
  const insurancesKey = JSON.stringify((data.insurances||[]).map(i => i.id + i.nextPaymentDate + i.annualPremium));
  const recurringKey  = JSON.stringify(data.expenses.filter(e=>e.isRecurring).map(e=>e.id+e.nextDueDate+e.status));
  useEffect(() => {
    if (!loaded) return;
    setDataRaw(prev => {
      const updated = autoGenerateMortgageExpenses(prev);
      if (updated !== prev) { saveToStorage(updated); return updated; }
      return prev;
    });
  }, [loaded, mortgagesKey]); // eslint-disable-line
  useEffect(() => {
    if (!loaded) return;
    setDataRaw(prev => {
      const updated = autoGenerateInsuranceExpenses(prev);
      if (updated !== prev) { saveToStorage(updated); return updated; }
      return prev;
    });
  }, [loaded, insurancesKey]); // eslint-disable-line
  useEffect(() => {
    if (!loaded) return;
    setDataRaw(prev => {
      const updated = advanceRecurringExpenses(prev);
      if (updated !== prev) { saveToStorage(updated); return updated; }
      return prev;
    });
  }, [loaded, recurringKey]); // eslint-disable-line

  const setData = useCallback(u => {
    setDataRaw(prev => { const next = typeof u === "function" ? u(prev) : u; saveToStorage(next); return next; });
  }, []);

  const alerts = {
    payments: data.payments.filter(p=>p.status==="pending"||p.status==="overdue").length,
    incidents: data.incidents.filter(i=>i.status!=="resolved").length,
    tenants: data.tenants.filter(t=>{ const d=(new Date(t.contractEnd)-new Date())/86400000; return d>=0&&d<=60; }).length,
  };

  const pages = { dashboard:Dashboard, properties:Properties, tenants:Tenants, payments:Payments, expenses:Expenses, incidents:Incidents, mortgages:Mortgages, documents:Documents, insurances:Insurances, contacts:Contacts, movimientos:Movimientos, finance:Finance, renta:Renta, settings:Settings };
  const Page = pages[tab];

  if (!loaded) return <div style={{ minHeight:"100vh",background:C.bg,display:"flex",alignItems:"center",justifyContent:"center",fontFamily:font,fontSize:22,color:C.textMuted }}>Cargando...</div>;

  const NavItems = ({ onClick }) => TABS.map(t => {
    const active = tab === t.id, alert = alerts[t.id];
    return (
      <button key={t.id} onClick={() => { setTab(t.id); onClick?.(); }} style={{ width:"100%",display:"flex",alignItems:"center",gap:10,padding:"10px 12px",borderRadius:10,border:"none",cursor:"pointer",marginBottom:2,background:active?C.accent:"transparent",color:active?"#fff":"rgba(255,255,255,0.5)",fontWeight:active?700:500,fontSize:13.5,textAlign:"left",fontFamily:fontSans,transition:"all 0.15s" }}>
        <span style={{ fontSize:15 }}>{t.icon}</span>{t.label}
        {alert>0&&<span style={{ marginLeft:"auto",background:active?"rgba(255,255,255,0.25)":C.red,color:"#fff",borderRadius:10,padding:"1px 7px",fontSize:11,fontWeight:700 }}>{alert}</span>}
      </button>
    );
  });

  return (
    <div style={{ minHeight:"100vh",background:C.bg,fontFamily:fontSans }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Playfair+Display:wght@700;800&family=DM+Sans:wght@400;500;600;700;800&display=swap');
        *{box-sizing:border-box;margin:0;padding:0;}
        button:hover{opacity:0.82;}
        input:focus,select:focus,textarea:focus{border-color:${C.accent}!important;box-shadow:0 0 0 3px ${C.accentLight};outline:none;}
        ::-webkit-scrollbar{width:6px;height:6px;} ::-webkit-scrollbar-thumb{background:${C.border};border-radius:3px;} ::-webkit-scrollbar-track{background:transparent;}
        .sidebar{display:flex!important;}
        .topbar{display:none!important;}
        @media(max-width:680px){.sidebar{display:none!important;} .topbar{display:flex!important;} .main{margin-left:0!important;padding:16px!important;padding-top:62px!important;}}
      `}</style>

      {/* Mobile topbar */}
      <div className="topbar" style={{ position:"fixed",top:0,left:0,right:0,height:56,background:"#1a1208",zIndex:60,alignItems:"center",padding:"0 16px",gap:12,borderBottom:"1px solid rgba(255,255,255,0.08)" }}>
        <button onClick={()=>setMenu(o=>!o)} style={{ background:"none",border:"none",color:"#fff",fontSize:24,cursor:"pointer",padding:4,lineHeight:1 }}>☰</button>
        <span style={{ fontFamily:font,color:"#fff",fontWeight:800,fontSize:18 }}>RentaFácil</span>
        <span style={{ marginLeft:"auto",fontFamily:fontSans,color:"rgba(255,255,255,0.45)",fontSize:13 }}>{TABS.find(t=>t.id===tab)?.label}</span>
      </div>

      {/* Mobile drawer */}
      {menu&&<div style={{ position:"fixed",inset:0,zIndex:70,display:"flex" }} onClick={()=>setMenu(false)}>
        <div style={{ width:230,background:"#1a1208",height:"100%",padding:"20px 10px",overflowY:"auto" }} onClick={e=>e.stopPropagation()}>
          <div style={{ fontFamily:font,color:"#fff",fontSize:20,fontWeight:800,padding:"6px 12px 16px" }}>RentaFácil</div>
          <NavItems onClick={()=>setMenu(false)} />
        </div>
        <div style={{ flex:1,background:"rgba(0,0,0,0.4)" }} />
      </div>}

      {/* Desktop sidebar */}
      <aside className="sidebar" style={{ position:"fixed",left:0,top:0,bottom:0,width:222,background:"#1a1208",flexDirection:"column",zIndex:50 }}>
        <div style={{ padding:"24px 20px 14px" }}>
          <div style={{ fontFamily:font,color:"#fff",fontSize:21,fontWeight:800,letterSpacing:"-0.5px" }}>RentaFácil</div>
          <div style={{ color:"rgba(255,255,255,0.28)",fontSize:12,marginTop:3,fontFamily:fontSans }}>{data.properties.length} pisos · {data.tenants.length + 1} inquilinos</div>
        </div>
        <div style={{ height:1,background:"rgba(255,255,255,0.07)",margin:"0 14px 10px" }} />
        <nav style={{ flex:1,padding:"0 10px",overflowY:"auto" }}><NavItems /></nav>
        <div style={{ padding:"12px 16px",borderTop:"1px solid rgba(255,255,255,0.07)" }}>
          <div style={{ fontSize:11,color:"rgba(255,255,255,0.17)",fontFamily:fontSans,textAlign:"center" }}>💾 Guardado automático</div>
        </div>
      </aside>

      {/* Main */}
      <main className="main" style={{ marginLeft:222,padding:"28px 30px",minHeight:"100vh" }}>
        <div style={{ maxWidth:1120 }}><Page data={data} setData={setData} go={setTab} /></div>
      </main>
    </div>
  );
}
